export interface GlossaryEntry {
  slug: string;
  term: { de: string; en: string; ru: string };
  definition: { de: string; en: string; ru: string };
  category: string;
  relatedTerms: string[];
  relatedServices: string[];
}

export const glossaryEntries: GlossaryEntry[] = [
  { slug: "achtsamkeit", term: { de: "Achtsamkeit", en: "Mindfulness", ru: "Осознанность" }, definition: { de: "Achtsamkeit ist die Fähigkeit, den gegenwärtigen Moment bewusst und ohne Bewertung wahrzunehmen. In der Führung ermöglicht sie klarere Entscheidungen und authentischere Beziehungen zu Mitarbeitern und Stakeholdern.", en: "Mindfulness is the ability to consciously perceive the present moment without judgment. In leadership, it enables clearer decisions and more authentic relationships with employees and stakeholders.", ru: "Осознанность — способность воспринимать настоящий момент сознательно и без оценки. В лидерстве она позволяет принимать более ясные решения и строить аутентичные отношения с сотрудниками." }, category: "bewusstsein", relatedTerms: ["praesenz", "bewusstsein", "meditation"], relatedServices: ["coaching", "seminare"] },
  { slug: "bewusstsein", term: { de: "Bewusstsein", en: "Consciousness", ru: "Сознание" }, definition: { de: "Bewusstsein bezeichnet die Gesamtheit unserer Wahrnehmung, Gedanken und Empfindungen. In Anatoly Mooks Arbeit wird Bewusstsein als Schlüssel zu persönlicher Meisterschaft und bewusster Führung verstanden — als Fundament für alle anderen Kompetenzen.", en: "Consciousness refers to the totality of our perception, thoughts, and sensations. In Anatoly Mook's work, consciousness is understood as the key to personal mastery and conscious leadership — as the foundation for all other competencies.", ru: "Сознание охватывает всю совокупность восприятия, мыслей и ощущений. В работе Анатолия Мука сознание понимается как ключ к личному мастерству и осознанному лидерству — как основа всех компетенций." }, category: "bewusstsein", relatedTerms: ["bewusstseinsentwicklung", "achtsamkeit", "selbstbewusstsein"], relatedServices: ["coaching", "seminare"] },
  { slug: "bewusstseinsentwicklung", term: { de: "Bewusstseinsentwicklung", en: "Consciousness Development", ru: "Развитие сознания" }, definition: { de: "Bewusstseinsentwicklung ist der gezielte Prozess, die eigene Wahrnehmungsfähigkeit zu erweitern. Sie ermöglicht tieferes Verständnis von sich selbst und anderen, bessere Entscheidungen und authentischeres Handeln in allen Lebensbereichen.", en: "Consciousness development is the deliberate process of expanding one's perceptual capacity. It enables deeper understanding of self and others, better decisions, and more authentic action in all areas of life.", ru: "Развитие сознания — целенаправленный процесс расширения способности восприятия. Оно даёт более глубокое понимание себя и других, лучшие решения и более аутентичные действия во всех сферах жизни." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "selbsterkenntnis", "transformation"], relatedServices: ["coaching", "seminare"] },
  { slug: "gegenwaertigkeit", term: { de: "Gegenwärtigkeit", en: "Presence", ru: "Присутствие в моменте" }, definition: { de: "Gegenwärtigkeit ist die Qualität, vollständig im aktuellen Moment präsent zu sein. Führungskräfte mit hoher Gegenwärtigkeit sind aufmerksamer, empathischer und treffen Entscheidungen mit größerer Klarheit.", en: "Presence is the quality of being fully present in the current moment. Leaders with high presence are more attentive, empathetic, and make decisions with greater clarity.", ru: "Присутствие в моменте — качество полного пребывания в настоящем. Руководители с высоким присутствием внимательнее, эмпатичнее и принимают решения с большей ясностью." }, category: "bewusstsein", relatedTerms: ["praesenz", "achtsamkeit", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "innere-klarheit", term: { de: "Innere Klarheit", en: "Inner Clarity", ru: "Внутренняя ясность" }, definition: { de: "Innere Klarheit ist der Zustand, in dem Gedanken, Gefühle und Handlungen in Einklang sind. Sie ermöglicht authentische Entscheidungen frei von Verwirrung und äußerem Druck — ein Kernelement in Anatoly Mooks Methode.", en: "Inner clarity is the state where thoughts, feelings, and actions are in alignment. It enables authentic decisions free from confusion and external pressure — a core element of Anatoly Mook's method.", ru: "Внутренняя ясность — состояние, когда мысли, чувства и действия находятся в гармонии. Она позволяет принимать аутентичные решения свободно от замешательства и внешнего давления." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "achtsamkeit", "entscheidungsstaerke"], relatedServices: ["coaching", "seminare"] },
  { slug: "meditation", term: { de: "Meditation", en: "Meditation", ru: "Медитация" }, definition: { de: "Meditation ist eine Praxis der bewussten Aufmerksamkeitslenkung, die zu tieferer Ruhe und Klarheit führt. In der professionellen Anwendung stärkt sie Fokus, Stressresistenz und die Fähigkeit zu bewussten Entscheidungen.", en: "Meditation is a practice of conscious attention direction that leads to deeper calm and clarity. In professional application, it strengthens focus, stress resistance, and the ability to make conscious decisions.", ru: "Медитация — практика осознанного направления внимания, ведущая к глубокому покою и ясности. В профессиональном применении она укрепляет фокус, стрессоустойчивость и способность к осознанным решениям." }, category: "bewusstsein", relatedTerms: ["achtsamkeit", "praesenz", "innere-klarheit"], relatedServices: ["seminare"] },
  { slug: "praesenz", term: { de: "Präsenz", en: "Presence", ru: "Присутствие" }, definition: { de: "Präsenz beschreibt die Fähigkeit, mit voller Aufmerksamkeit im Hier und Jetzt zu sein. In Führungskontexten strahlt Präsenz Sicherheit und Vertrauen aus und ist Grundlage für wirkungsvolle Kommunikation.", en: "Presence describes the ability to be fully attentive in the here and now. In leadership contexts, presence radiates security and trust, forming the foundation for effective communication.", ru: "Присутствие описывает способность быть полностью внимательным здесь и сейчас. В контексте лидерства присутствие излучает безопасность и доверие, являясь основой эффективной коммуникации." }, category: "bewusstsein", relatedTerms: ["gegenwaertigkeit", "achtsamkeit", "authentische-fuehrung"], relatedServices: ["coaching", "keynotes"] },
  { slug: "selbstbewusstsein", term: { de: "Selbstbewusstsein", en: "Self-Awareness", ru: "Самосознание" }, definition: { de: "Selbstbewusstsein ist das Wissen um die eigenen Stärken, Schwächen, Werte und Muster. Es ist die Basis für persönliches Wachstum und bewusste Führung — ohne Selbstbewusstsein keine echte Transformation.", en: "Self-awareness is knowing your own strengths, weaknesses, values, and patterns. It is the foundation for personal growth and conscious leadership — without self-awareness, no true transformation.", ru: "Самосознание — знание собственных сильных и слабых сторон, ценностей и паттернов. Оно — основа личного роста и осознанного лидерства. Без самосознания нет настоящей трансформации." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "selbsterkenntnis", "emotionale-intelligenz"], relatedServices: ["coaching"] },
  { slug: "authentische-fuehrung", term: { de: "Authentische Führung", en: "Authentic Leadership", ru: "Аутентичное лидерство" }, definition: { de: "Authentische Führung basiert auf Selbstkenntnis, Transparenz und wertebasiertem Handeln. Authentische Führungskräfte inspirieren durch Kongruenz zwischen Worten und Taten statt durch Macht oder Manipulation.", en: "Authentic leadership is based on self-knowledge, transparency, and values-based action. Authentic leaders inspire through congruence between words and deeds rather than through power or manipulation.", ru: "Аутентичное лидерство основано на самопознании, прозрачности и действиях на основе ценностей. Аутентичные лидеры вдохновляют через конгруэнтность слов и дел, а не через власть или манипуляции." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "integritaet", "servant-leadership"], relatedServices: ["coaching", "corporate"] },
  { slug: "bewusste-fuehrung", term: { de: "Bewusste Führung", en: "Conscious Leadership", ru: "Осознанное лидерство" }, definition: { de: "Bewusste Führung vereint Selbstkenntnis, Empathie und strategische Klarheit. Sie bedeutet, Entscheidungen reflektiert statt reaktiv zu treffen und Teams durch Präsenz und Vertrauen statt Kontrolle zu leiten.", en: "Conscious leadership combines self-knowledge, empathy, and strategic clarity. It means making decisions reflectively rather than reactively and guiding teams through presence and trust rather than control.", ru: "Осознанное лидерство объединяет самопознание, эмпатию и стратегическую ясность. Оно означает рефлективное принятие решений и ведение команд через присутствие и доверие, а не контроль." }, category: "fuehrung", relatedTerms: ["authentische-fuehrung", "empowerment", "fuehrungsstil"], relatedServices: ["coaching", "corporate", "keynotes"] },
  { slug: "empowerment", term: { de: "Empowerment", en: "Empowerment", ru: "Расширение полномочий" }, definition: { de: "Empowerment bezeichnet die Befähigung und Ermächtigung von Mitarbeitern, eigenverantwortlich zu handeln. Es schafft Innovation, Engagement und eine Kultur des Vertrauens innerhalb von Organisationen.", en: "Empowerment refers to enabling and empowering employees to act independently. It creates innovation, engagement, and a culture of trust within organizations.", ru: "Расширение полномочий — наделение сотрудников правом действовать самостоятельно. Оно создаёт инновации, вовлечённость и культуру доверия в организациях." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "servant-leadership", "agilitat"], relatedServices: ["corporate"] },
  { slug: "fuehrungsstil", term: { de: "Führungsstil", en: "Leadership Style", ru: "Стиль лидерства" }, definition: { de: "Der Führungsstil beschreibt die charakteristische Art, wie eine Führungskraft ihre Rolle ausfüllt. Bewusste Führungskräfte wählen ihren Stil situativ und reflektiert statt aus Gewohnheit oder Unsicherheit.", en: "Leadership style describes the characteristic way a leader fulfills their role. Conscious leaders choose their style situationally and reflectively rather than out of habit or insecurity.", ru: "Стиль лидерства описывает характерный способ, которым руководитель выполняет свою роль. Осознанные лидеры выбирают стиль ситуативно и рефлективно, а не по привычке." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "situative-fuehrung", "servant-leadership"], relatedServices: ["coaching", "corporate"] },
  { slug: "leadership", term: { de: "Leadership", en: "Leadership", ru: "Лидерство" }, definition: { de: "Leadership geht über Management hinaus — es ist die Fähigkeit, Menschen zu inspirieren, eine gemeinsame Vision zu verfolgen. Echtes Leadership entsteht aus innerer Klarheit und der Bereitschaft, Verantwortung zu tragen.", en: "Leadership goes beyond management — it is the ability to inspire people to pursue a shared vision. True leadership arises from inner clarity and the willingness to bear responsibility.", ru: "Лидерство выходит за рамки менеджмента — это способность вдохновлять людей следовать общему видению. Настоящее лидерство рождается из внутренней ясности и готовности нести ответственность." }, category: "fuehrung", relatedTerms: ["bewusste-fuehrung", "visionaere-fuehrung", "authentische-fuehrung"], relatedServices: ["coaching", "keynotes"] },
  { slug: "servant-leadership", term: { de: "Servant Leadership", en: "Servant Leadership", ru: "Служащее лидерство" }, definition: { de: "Servant Leadership stellt die Bedürfnisse der Mitarbeiter und der Organisation vor die eigenen Interessen der Führungskraft. Dieser Ansatz fördert Vertrauen, Autonomie und eine nachhaltige Leistungskultur.", en: "Servant Leadership puts the needs of employees and the organization before the leader's own interests. This approach fosters trust, autonomy, and a sustainable performance culture.", ru: "Служащее лидерство ставит потребности сотрудников и организации выше личных интересов руководителя. Этот подход способствует доверию, автономии и устойчивой культуре результативности." }, category: "fuehrung", relatedTerms: ["empowerment", "bewusste-fuehrung", "authentische-fuehrung"], relatedServices: ["corporate", "coaching"] },
  { slug: "situative-fuehrung", term: { de: "Situative Führung", en: "Situational Leadership", ru: "Ситуативное лидерство" }, definition: { de: "Situative Führung passt den Führungsstil an die Reife und Kompetenz der Mitarbeiter sowie an die jeweilige Situation an. Es erfordert hohe Bewusstheit und die Fähigkeit, flexibel zwischen Stilen zu wechseln.", en: "Situational leadership adapts the leadership style to the maturity and competence of employees and to the specific situation. It requires high awareness and the ability to flexibly switch between styles.", ru: "Ситуативное лидерство адаптирует стиль руководства к зрелости и компетенции сотрудников и конкретной ситуации. Оно требует высокой осознанности и способности гибко переключаться между стилями." }, category: "fuehrung", relatedTerms: ["fuehrungsstil", "bewusste-fuehrung", "empowerment"], relatedServices: ["corporate"] },
  { slug: "visionaere-fuehrung", term: { de: "Visionäre Führung", en: "Visionary Leadership", ru: "Визионерское лидерство" }, definition: { de: "Visionäre Führung inspiriert durch ein klares Bild der Zukunft und die Fähigkeit, andere für diese Vision zu begeistern. Sie verbindet strategisches Denken mit emotionaler Intelligenz und innerem Feuer.", en: "Visionary leadership inspires through a clear picture of the future and the ability to enthuse others for this vision. It combines strategic thinking with emotional intelligence and inner fire.", ru: "Визионерское лидерство вдохновляет ясной картиной будущего и способностью увлечь других этим видением. Оно сочетает стратегическое мышление с эмоциональным интеллектом и внутренним огнём." }, category: "fuehrung", relatedTerms: ["leadership", "bewusste-fuehrung", "innere-klarheit"], relatedServices: ["keynotes", "coaching"] },
  { slug: "executive-coaching", term: { de: "Executive Coaching", en: "Executive Coaching", ru: "Коучинг руководителей" }, definition: { de: "Executive Coaching ist eine professionelle Begleitung für Führungskräfte auf höchster Ebene. Es adressiert komplexe Herausforderungen wie strategische Entscheidungen, Stakeholder-Management und persönliche Weiterentwicklung in Verantwortungspositionen.", en: "Executive coaching is professional accompaniment for leaders at the highest level. It addresses complex challenges such as strategic decisions, stakeholder management, and personal development in positions of responsibility.", ru: "Коучинг руководителей — профессиональное сопровождение лидеров на высшем уровне. Он адресует сложные вызовы: стратегические решения, управление стейкхолдерами и личное развитие на ответственных позициях." }, category: "coaching", relatedTerms: ["einzelcoaching", "mentoring", "sparring"], relatedServices: ["coaching"] },
  { slug: "einzelcoaching", term: { de: "Einzelcoaching", en: "Individual Coaching", ru: "Индивидуальный коучинг" }, definition: { de: "Einzelcoaching ist die intensivste Form der persönlichen Begleitung. In vertraulichem Rahmen arbeiten Coach und Klient an individuellen Zielen, Herausforderungen und persönlichem Wachstum.", en: "Individual coaching is the most intensive form of personal accompaniment. In a confidential setting, coach and client work on individual goals, challenges, and personal growth.", ru: "Индивидуальный коучинг — наиболее интенсивная форма персонального сопровождения. В конфиденциальной обстановке коуч и клиент работают над целями, вызовами и личным ростом." }, category: "coaching", relatedTerms: ["executive-coaching", "mentoring", "systemisches-coaching"], relatedServices: ["coaching"] },
  { slug: "gruppencoaching", term: { de: "Gruppencoaching", en: "Group Coaching", ru: "Групповой коучинг" }, definition: { de: "Gruppencoaching nutzt die Dynamik und Diversität einer Gruppe, um individuelle und kollektive Lernprozesse zu fördern. Teilnehmer profitieren von verschiedenen Perspektiven und gegenseitiger Unterstützung.", en: "Group coaching uses the dynamics and diversity of a group to promote individual and collective learning processes. Participants benefit from different perspectives and mutual support.", ru: "Групповой коучинг использует динамику и разнообразие группы для развития индивидуальных и коллективных процессов обучения. Участники выигрывают от разных перспектив и взаимной поддержки." }, category: "coaching", relatedTerms: ["team-coaching", "einzelcoaching", "workshop"], relatedServices: ["seminare", "corporate"] },
  { slug: "mentoring", term: { de: "Mentoring", en: "Mentoring", ru: "Менторинг" }, definition: { de: "Mentoring ist eine Beziehung, in der ein erfahrener Mentor sein Wissen, seine Erfahrung und seine Netzwerke mit dem Mentee teilt. Es verbindet persönliche Entwicklung mit praktischer Lebens- und Berufserfahrung.", en: "Mentoring is a relationship in which an experienced mentor shares their knowledge, experience, and networks with the mentee. It combines personal development with practical life and professional experience.", ru: "Менторинг — отношения, в которых опытный ментор делится знаниями, опытом и связями с менти. Он сочетает личное развитие с практическим жизненным и профессиональным опытом." }, category: "coaching", relatedTerms: ["executive-coaching", "sparring", "einzelcoaching"], relatedServices: ["coaching"] },
  { slug: "systemisches-coaching", term: { de: "Systemisches Coaching", en: "Systemic Coaching", ru: "Системный коучинг" }, definition: { de: "Systemisches Coaching betrachtet den Menschen im Kontext seiner Beziehungen und Systeme. Es erkennt, dass Veränderung in einem Bereich Auswirkungen auf das gesamte System hat, und nutzt diese Erkenntnis für nachhaltige Transformation.", en: "Systemic coaching views the person in the context of their relationships and systems. It recognizes that change in one area impacts the entire system and uses this insight for sustainable transformation.", ru: "Системный коучинг рассматривает человека в контексте его отношений и систем. Он признаёт, что изменение в одной области влияет на всю систему, и использует это для устойчивой трансформации." }, category: "coaching", relatedTerms: ["einzelcoaching", "team-coaching", "organisationsentwicklung"], relatedServices: ["coaching", "corporate"] },
  { slug: "team-coaching", term: { de: "Team Coaching", en: "Team Coaching", ru: "Командный коучинг" }, definition: { de: "Team Coaching entwickelt die Leistungsfähigkeit und Zusammenarbeit eines Teams als Ganzes. Es adressiert Gruppendynamiken, Kommunikationsmuster und die gemeinsame Ausrichtung auf Ziele.", en: "Team coaching develops the performance and collaboration of a team as a whole. It addresses group dynamics, communication patterns, and shared alignment toward goals.", ru: "Командный коучинг развивает эффективность и сотрудничество команды как целого. Он работает с групповой динамикой, паттернами коммуникации и общей направленностью на цели." }, category: "coaching", relatedTerms: ["gruppencoaching", "systemisches-coaching", "empowerment"], relatedServices: ["corporate"] },
  { slug: "supervision", term: { de: "Supervision", en: "Supervision", ru: "Супервизия" }, definition: { de: "Supervision ist die professionelle Reflexion beruflichen Handelns. Sie hilft Fachkräften und Führungskräften, ihre Arbeit zu reflektieren, blinde Flecken zu erkennen und die Qualität ihrer Beziehungsarbeit zu verbessern.", en: "Supervision is the professional reflection of professional action. It helps professionals and leaders reflect on their work, recognize blind spots, and improve the quality of their relational work.", ru: "Супервизия — профессиональная рефлексия деятельности. Она помогает специалистам и руководителям осмыслять работу, распознавать слепые зоны и улучшать качество межличностного взаимодействия." }, category: "coaching", relatedTerms: ["reflexion", "sparring", "feedback"], relatedServices: ["coaching"] },
  { slug: "sparring", term: { de: "Sparring", en: "Sparring", ru: "Спарринг" }, definition: { de: "Sparring ist ein Dialog auf Augenhöhe, bei dem Ideen, Strategien und Entscheidungen kritisch hinterfragt werden. Es bietet Führungskräften einen geschützten Raum, um Gedanken zu schärfen und neue Perspektiven zu gewinnen.", en: "Sparring is a dialogue at eye level where ideas, strategies, and decisions are critically questioned. It provides leaders with a safe space to sharpen thoughts and gain new perspectives.", ru: "Спарринг — диалог на равных, где идеи, стратегии и решения критически проверяются. Он предоставляет руководителям безопасное пространство для заточки мыслей и обретения новых перспектив." }, category: "coaching", relatedTerms: ["mentoring", "executive-coaching", "reflexion"], relatedServices: ["coaching"] },
  { slug: "persoenliche-transformation", term: { de: "Persönliche Transformation", en: "Personal Transformation", ru: "Личная трансформация" }, definition: { de: "Persönliche Transformation ist ein tiefgreifender Wandel in Wahrnehmung, Denken und Handeln. Sie geht über oberflächliche Verhaltensänderung hinaus und berührt die Kernidentität eines Menschen.", en: "Personal transformation is a profound shift in perception, thinking, and action. It goes beyond superficial behavioral change and touches a person's core identity.", ru: "Личная трансформация — глубокий сдвиг в восприятии, мышлении и действиях. Она выходит за рамки поверхностных изменений поведения и затрагивает ядро идентичности." }, category: "transformation", relatedTerms: ["veraenderungsprozess", "wachstum", "bewusstseinsentwicklung"], relatedServices: ["transformation", "coaching"] },
  { slug: "resilienz", term: { de: "Resilienz", en: "Resilience", ru: "Стойкость" }, definition: { de: "Resilienz ist die Fähigkeit, mit Stress, Krisen und Rückschlägen konstruktiv umzugehen und gestärkt daraus hervorzugehen. Sie basiert auf Bewusstheit, Flexibilität und einem stabilen inneren Fundament.", en: "Resilience is the ability to constructively deal with stress, crises, and setbacks and emerge stronger. It is based on awareness, flexibility, and a stable inner foundation.", ru: "Стойкость — способность конструктивно справляться со стрессом, кризисами и неудачами, выходя из них сильнее. Она основана на осознанности, гибкости и стабильном внутреннем фундаменте." }, category: "transformation", relatedTerms: ["stress", "selbstwirksamkeit", "innere-klarheit"], relatedServices: ["coaching", "seminare"] },
  { slug: "veraenderungsprozess", term: { de: "Veränderungsprozess", en: "Change Process", ru: "Процесс изменений" }, definition: { de: "Ein Veränderungsprozess umfasst alle Phasen von der Erkenntnis der Notwendigkeit bis zur Integration neuer Verhaltensweisen. Bewusste Begleitung macht den Unterschied zwischen kurzfristiger Anpassung und nachhaltiger Transformation.", en: "A change process encompasses all phases from recognizing the necessity to integrating new behaviors. Conscious accompaniment makes the difference between short-term adjustment and sustainable transformation.", ru: "Процесс изменений охватывает все этапы от осознания необходимости до интеграции нового поведения. Осознанное сопровождение отличает краткосрочную адаптацию от устойчивой трансформации." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "wachstum", "gewohnheitsaenderung"], relatedServices: ["coaching", "transformation"] },
  { slug: "wachstum", term: { de: "Wachstum", en: "Growth", ru: "Рост" }, definition: { de: "Persönliches Wachstum ist die kontinuierliche Entwicklung von Fähigkeiten, Bewusstsein und Charakter. Es erfordert die Bereitschaft, die eigene Komfortzone zu verlassen und sich neuen Herausforderungen zu stellen.", en: "Personal growth is the continuous development of skills, awareness, and character. It requires the willingness to leave one's comfort zone and face new challenges.", ru: "Личный рост — непрерывное развитие навыков, осознанности и характера. Он требует готовности покинуть зону комфорта и принять новые вызовы." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "selbstoptimierung", "bewusstseinsentwicklung"], relatedServices: ["coaching", "seminare"] },
  { slug: "selbstoptimierung", term: { de: "Selbstoptimierung", en: "Self-Optimization", ru: "Самооптимизация" }, definition: { de: "Selbstoptimierung beschreibt den bewussten Prozess, die eigene Leistungsfähigkeit und Lebensqualität zu steigern. Im Kontext bewusster Führung geht es nicht um Perfektionismus, sondern um authentische Entfaltung des eigenen Potenzials.", en: "Self-optimization describes the conscious process of improving one's performance capacity and quality of life. In the context of conscious leadership, it is not about perfectionism but about authentic unfolding of one's potential.", ru: "Самооптимизация — осознанный процесс повышения работоспособности и качества жизни. В контексте осознанного лидерства речь не о перфекционизме, а об аутентичном раскрытии потенциала." }, category: "transformation", relatedTerms: ["wachstum", "persoenliche-transformation", "selbstwirksamkeit"], relatedServices: ["coaching"] },
  { slug: "identitaetsarbeit", term: { de: "Identitätsarbeit", en: "Identity Work", ru: "Работа с идентичностью" }, definition: { de: "Identitätsarbeit befasst sich mit der bewussten Auseinandersetzung mit dem eigenen Selbstbild, Rollen und Prägungen. Sie ermöglicht tiefgreifende Veränderung, indem sie an der Wurzel ansetzt statt nur an Symptomen.", en: "Identity work involves the conscious examination of one's self-image, roles, and conditioning. It enables profound change by addressing the root rather than just symptoms.", ru: "Работа с идентичностью — осознанное исследование самовосприятия, ролей и обусловленностей. Она позволяет глубокие изменения, работая с корнем, а не только с симптомами." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "selbstbewusstsein", "selbsterkenntnis"], relatedServices: ["coaching"] },
  { slug: "gewohnheitsaenderung", term: { de: "Gewohnheitsänderung", en: "Habit Change", ru: "Изменение привычек" }, definition: { de: "Gewohnheitsänderung erfordert mehr als Willenskraft — sie braucht Bewusstheit über die zugrundeliegenden Auslöser und Belohnungsmuster. Nachhaltige Gewohnheitsänderung entsteht durch Verständnis, nicht durch Zwang.", en: "Habit change requires more than willpower — it needs awareness of the underlying triggers and reward patterns. Sustainable habit change comes through understanding, not through force.", ru: "Изменение привычек требует большего, чем сила воли — осознания скрытых триггеров и паттернов вознаграждения. Устойчивое изменение привычек приходит через понимание, а не через принуждение." }, category: "transformation", relatedTerms: ["veraenderungsprozess", "selbstoptimierung", "prokrastination"], relatedServices: ["coaching"] },
  { slug: "neuausrichtung", term: { de: "Neuausrichtung", en: "Realignment", ru: "Переориентация" }, definition: { de: "Neuausrichtung ist der bewusste Prozess, Lebens- oder Karriereziele neu zu definieren und den eigenen Kurs zu korrigieren. Sie entsteht oft in Umbruchphasen und erfordert Mut, Klarheit und einen vertrauenswürdigen Sparring-Partner.", en: "Realignment is the conscious process of redefining life or career goals and correcting one's course. It often arises during transition phases and requires courage, clarity, and a trustworthy sparring partner.", ru: "Переориентация — осознанный процесс переопределения целей и корректировки курса. Часто возникает в переходные периоды и требует мужества, ясности и доверенного партнёра для спарринга." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "innere-klarheit", "veraenderungsprozess"], relatedServices: ["coaching", "transformation"] },
  { slug: "agilitat", term: { de: "Agilität", en: "Agility", ru: "Гибкость" }, definition: { de: "Agilität beschreibt die Fähigkeit von Organisationen und Individuen, schnell und flexibel auf Veränderungen zu reagieren. Wahre Agilität basiert auf bewusster Führung und einer Kultur des Vertrauens.", en: "Agility describes the ability of organizations and individuals to react quickly and flexibly to changes. True agility is based on conscious leadership and a culture of trust.", ru: "Гибкость описывает способность организаций и людей быстро и гибко реагировать на изменения. Истинная гибкость основана на осознанном лидерстве и культуре доверия." }, category: "business", relatedTerms: ["new-work", "organisationsentwicklung", "unternehmenskultur"], relatedServices: ["corporate"] },
  { slug: "corporate-culture", term: { de: "Corporate Culture", en: "Corporate Culture", ru: "Корпоративная культура" }, definition: { de: "Corporate Culture umfasst die gemeinsamen Werte, Normen und Verhaltensweisen in einem Unternehmen. Eine bewusste Unternehmenskultur entsteht nicht durch Leitbilder an der Wand, sondern durch gelebte Führung.", en: "Corporate culture encompasses the shared values, norms, and behaviors in a company. A conscious corporate culture does not emerge from mission statements on the wall but through lived leadership.", ru: "Корпоративная культура охватывает общие ценности, нормы и модели поведения в компании. Осознанная корпоративная культура возникает не из лозунгов на стене, а через живое лидерство." }, category: "business", relatedTerms: ["unternehmenskultur", "agilitat", "organisationsentwicklung"], relatedServices: ["corporate"] },
  { slug: "new-work", term: { de: "New Work", en: "New Work", ru: "Новая работа" }, definition: { de: "New Work beschreibt neue Arbeitsformen, die auf Selbstbestimmung, Sinnhaftigkeit und Gemeinschaft basieren. Bewusste Führung ist der Schlüssel, damit New Work nicht nur ein Schlagwort bleibt.", en: "New Work describes new forms of work based on self-determination, meaningfulness, and community. Conscious leadership is the key to ensuring New Work does not remain just a buzzword.", ru: "New Work описывает новые формы работы, основанные на самоопределении, осмысленности и общности. Осознанное лидерство — ключ к тому, чтобы New Work не осталась лишь модным словом." }, category: "business", relatedTerms: ["agilitat", "unternehmenskultur", "empowerment"], relatedServices: ["corporate", "keynotes"] },
  { slug: "organisationsentwicklung", term: { de: "Organisationsentwicklung", en: "Organizational Development", ru: "Организационное развитие" }, definition: { de: "Organisationsentwicklung ist ein geplanter, systematischer Prozess zur Verbesserung der Leistungsfähigkeit und Gesundheit einer Organisation. Sie beginnt immer bei den Führungskräften und ihrer Bewusstheit.", en: "Organizational development is a planned, systematic process for improving the performance and health of an organization. It always begins with leaders and their awareness.", ru: "Организационное развитие — планомерный процесс улучшения эффективности и здоровья организации. Оно всегда начинается с руководителей и их осознанности." }, category: "business", relatedTerms: ["corporate-culture", "agilitat", "unternehmenskultur"], relatedServices: ["corporate"] },
  { slug: "unternehmenskultur", term: { de: "Unternehmenskultur", en: "Company Culture", ru: "Культура компании" }, definition: { de: "Unternehmenskultur ist das unsichtbare Betriebssystem einer Organisation — sie bestimmt, wie Entscheidungen getroffen, Konflikte gelöst und Innovation gelebt wird. Kulturwandel beginnt bei bewusster Führung.", en: "Company culture is the invisible operating system of an organization — it determines how decisions are made, conflicts resolved, and innovation practiced. Cultural change begins with conscious leadership.", ru: "Культура компании — невидимая операционная система организации. Она определяет, как принимаются решения, разрешаются конфликты и практикуются инновации. Культурные изменения начинаются с осознанного лидерства." }, category: "business", relatedTerms: ["corporate-culture", "organisationsentwicklung", "bewusste-fuehrung"], relatedServices: ["corporate"] },
  { slug: "innovation", term: { de: "Innovation", en: "Innovation", ru: "Инновация" }, definition: { de: "Innovation entsteht nicht durch Prozesse allein, sondern durch ein Klima der psychologischen Sicherheit und bewussten Kreativität. Führungskräfte, die Raum für Neues schaffen, fördern echte Innovation.", en: "Innovation does not come from processes alone but from a climate of psychological safety and conscious creativity. Leaders who create space for the new foster genuine innovation.", ru: "Инновация возникает не только из процессов, а из климата психологической безопасности и осознанной креативности. Руководители, создающие пространство для нового, способствуют настоящим инновациям." }, category: "business", relatedTerms: ["agilitat", "new-work", "unternehmenskultur"], relatedServices: ["corporate", "keynotes"] },
  { slug: "nachhaltigkeit", term: { de: "Nachhaltigkeit", en: "Sustainability", ru: "Устойчивость" }, definition: { de: "Nachhaltigkeit in der Führung bedeutet, langfristiges Denken und Handeln in den Mittelpunkt zu stellen. Nachhaltige Führung schafft Wert für alle Stakeholder, nicht nur kurzfristigen Profit.", en: "Sustainability in leadership means placing long-term thinking and action at the center. Sustainable leadership creates value for all stakeholders, not just short-term profit.", ru: "Устойчивость в лидерстве означает фокус на долгосрочном мышлении и действиях. Устойчивое лидерство создаёт ценность для всех заинтересованных сторон, а не только краткосрочную прибыль." }, category: "business", relatedTerms: ["verantwortung", "ethik", "bewusste-fuehrung"], relatedServices: ["corporate"] },
  { slug: "employer-branding", term: { de: "Employer Branding", en: "Employer Branding", ru: "Бренд работодателя" }, definition: { de: "Employer Branding ist die strategische Positionierung als attraktiver Arbeitgeber. Authentisches Employer Branding beginnt mit einer gelebten, bewussten Unternehmenskultur, die Talente natürlich anzieht.", en: "Employer branding is the strategic positioning as an attractive employer. Authentic employer branding begins with a lived, conscious corporate culture that naturally attracts talent.", ru: "Бренд работодателя — стратегическое позиционирование как привлекательного работодателя. Аутентичный бренд начинается с живой, осознанной корпоративной культуры, естественно привлекающей таланты." }, category: "business", relatedTerms: ["unternehmenskultur", "corporate-culture", "new-work"], relatedServices: ["corporate"] },
  { slug: "assessment", term: { de: "Assessment", en: "Assessment", ru: "Оценка" }, definition: { de: "Assessment-Verfahren erfassen den Entwicklungsstand, Potenziale und Muster einer Person oder eines Teams. Sie bilden die Grundlage für gezielte Coaching- und Entwicklungsmaßnahmen.", en: "Assessment procedures capture the development level, potentials, and patterns of a person or team. They form the basis for targeted coaching and development measures.", ru: "Процедуры оценки фиксируют уровень развития, потенциалы и паттерны человека или команды. Они составляют основу для целенаправленного коучинга и развития." }, category: "methodik", relatedTerms: ["feedback", "reflexion", "einzelcoaching"], relatedServices: ["coaching", "corporate"] },
  { slug: "feedback", term: { de: "Feedback", en: "Feedback", ru: "Обратная связь" }, definition: { de: "Feedback ist ein Werkzeug für Wachstum und Klarheit. Konstruktives Feedback zu geben und anzunehmen erfordert Bewusstheit, Mut und die Bereitschaft, die eigene Wahrnehmung zu hinterfragen.", en: "Feedback is a tool for growth and clarity. Giving and receiving constructive feedback requires awareness, courage, and the willingness to question one's own perception.", ru: "Обратная связь — инструмент роста и ясности. Давать и принимать конструктивную обратную связь требует осознанности, мужества и готовности ставить под вопрос собственное восприятие." }, category: "methodik", relatedTerms: ["assessment", "reflexion", "supervision"], relatedServices: ["coaching", "corporate"] },
  { slug: "journaling", term: { de: "Journaling", en: "Journaling", ru: "Ведение дневника" }, definition: { de: "Journaling ist die Praxis des strukturierten Schreibens zur Selbstreflexion. Es macht unbewusste Gedanken und Muster sichtbar und unterstützt die Integration von Coaching-Erkenntnissen im Alltag.", en: "Journaling is the practice of structured writing for self-reflection. It makes unconscious thoughts and patterns visible and supports the integration of coaching insights into daily life.", ru: "Ведение дневника — практика структурированного письма для саморефлексии. Оно делает видимыми неосознанные мысли и паттерны и помогает интегрировать инсайты коучинга в повседневную жизнь." }, category: "methodik", relatedTerms: ["reflexion", "selbstbewusstsein", "achtsamkeit"], relatedServices: ["coaching", "resources"] },
  { slug: "reflexion", term: { de: "Reflexion", en: "Reflection", ru: "Рефлексия" }, definition: { de: "Reflexion ist die bewusste Rückschau auf Erfahrungen, Handlungen und deren Auswirkungen. Regelmäßige Reflexion ist das Fundament persönlichen Wachstums und bewusster Führung.", en: "Reflection is the conscious review of experiences, actions, and their effects. Regular reflection is the foundation of personal growth and conscious leadership.", ru: "Рефлексия — осознанный анализ опыта, действий и их последствий. Регулярная рефлексия — фундамент личного роста и осознанного лидерства." }, category: "methodik", relatedTerms: ["journaling", "supervision", "selbstbewusstsein"], relatedServices: ["coaching"] },
  { slug: "retreat", term: { de: "Retreat", en: "Retreat", ru: "Ретрит" }, definition: { de: "Ein Retreat ist ein mehrtägiger Rückzug aus dem Alltag für intensive persönliche Arbeit. In der Stille und Konzentration eines Retreats entstehen tiefe Einsichten und nachhaltige Transformation.", en: "A retreat is a multi-day withdrawal from daily life for intensive personal work. In the stillness and concentration of a retreat, deep insights and sustainable transformation emerge.", ru: "Ретрит — многодневный уход от повседневности для интенсивной личной работы. В тишине и концентрации ретрита рождаются глубокие инсайты и устойчивая трансформация." }, category: "methodik", relatedTerms: ["meditation", "achtsamkeit", "persoenliche-transformation"], relatedServices: ["seminare"] },
  { slug: "visualisierung", term: { de: "Visualisierung", en: "Visualization", ru: "Визуализация" }, definition: { de: "Visualisierung ist eine mentale Technik, bei der gewünschte Ergebnisse bildhaft vorgestellt werden. In Coaching und Führung unterstützt sie die Klärung von Zielen und die Mobilisierung innerer Ressourcen.", en: "Visualization is a mental technique where desired outcomes are pictured mentally. In coaching and leadership, it supports goal clarification and the mobilization of inner resources.", ru: "Визуализация — ментальная техника, при которой желаемые результаты представляются в образах. В коучинге и лидерстве она помогает прояснить цели и мобилизовать внутренние ресурсы." }, category: "methodik", relatedTerms: ["meditation", "reflexion", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "workshop", term: { de: "Workshop", en: "Workshop", ru: "Воркшоп" }, definition: { de: "Ein Workshop ist ein interaktives Format, in dem Teilnehmer aktiv an einem Thema arbeiten. Workshops verbinden Wissensvermittlung mit praktischer Anwendung und Gruppenerfahrung.", en: "A workshop is an interactive format where participants actively work on a topic. Workshops combine knowledge transfer with practical application and group experience.", ru: "Воркшоп — интерактивный формат, где участники активно работают над темой. Воркшопы сочетают передачу знаний с практическим применением и групповым опытом." }, category: "methodik", relatedTerms: ["retreat", "gruppencoaching", "facilitation"], relatedServices: ["seminare"] },
  { slug: "facilitation", term: { de: "Facilitation", en: "Facilitation", ru: "Фасилитация" }, definition: { de: "Facilitation ist die Kunst, Gruppenprozesse so zu gestalten, dass alle Teilnehmer ihr Bestes einbringen können. Ein guter Facilitator schafft den Rahmen, ohne den Inhalt zu bestimmen.", en: "Facilitation is the art of designing group processes so that all participants can contribute their best. A good facilitator creates the framework without determining the content.", ru: "Фасилитация — искусство организации групповых процессов так, чтобы каждый участник мог внести лучшее. Хороший фасилитатор создаёт рамку, не определяя содержание." }, category: "methodik", relatedTerms: ["workshop", "gruppencoaching", "team-coaching"], relatedServices: ["corporate", "seminare"] },
  { slug: "burnout", term: { de: "Burnout", en: "Burnout", ru: "Выгорание" }, definition: { de: "Burnout ist ein Zustand emotionaler, körperlicher und geistiger Erschöpfung durch chronischen Stress. Bewusste Führung und Selbstkenntnis sind der beste Schutz — Prävention beginnt mit Bewusstheit.", en: "Burnout is a state of emotional, physical, and mental exhaustion from chronic stress. Conscious leadership and self-knowledge are the best protection — prevention begins with awareness.", ru: "Выгорание — состояние эмоционального, физического и ментального истощения от хронического стресса. Осознанное лидерство и самопознание — лучшая защита. Профилактика начинается с осознанности." }, category: "psychologie", relatedTerms: ["stress", "resilienz", "selbstwirksamkeit"], relatedServices: ["coaching"] },
  { slug: "emotionale-intelligenz", term: { de: "Emotionale Intelligenz", en: "Emotional Intelligence", ru: "Эмоциональный интеллект" }, definition: { de: "Emotionale Intelligenz ist die Fähigkeit, eigene und fremde Emotionen wahrzunehmen, zu verstehen und konstruktiv zu nutzen. Sie ist eine der wichtigsten Führungskompetenzen und kann gezielt entwickelt werden.", en: "Emotional intelligence is the ability to perceive, understand, and constructively use one's own and others' emotions. It is one of the most important leadership competencies and can be specifically developed.", ru: "Эмоциональный интеллект — способность воспринимать, понимать и конструктивно использовать собственные и чужие эмоции. Это одна из важнейших лидерских компетенций, которая целенаправленно развивается." }, category: "psychologie", relatedTerms: ["selbstbewusstsein", "empathie", "bewusste-fuehrung"], relatedServices: ["coaching", "corporate"] },
  { slug: "flow", term: { de: "Flow", en: "Flow", ru: "Поток" }, definition: { de: "Flow ist der Zustand vollständiger Vertiefung in eine Tätigkeit, in dem Zeit und Selbstbewusstsein in den Hintergrund treten. Bewusste Führungskräfte schaffen Bedingungen, die Flow für sich und ihre Teams fördern.", en: "Flow is the state of complete immersion in an activity where time and self-consciousness fade into the background. Conscious leaders create conditions that promote flow for themselves and their teams.", ru: "Поток — состояние полного погружения в деятельность, когда время и самосознание уходят на второй план. Осознанные лидеры создают условия, способствующие потоку для себя и своих команд." }, category: "psychologie", relatedTerms: ["praesenz", "motivation", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "intuition", term: { de: "Intuition", en: "Intuition", ru: "Интуиция" }, definition: { de: "Intuition ist die Fähigkeit, ohne bewusste Analyse zu richtigen Einschätzungen zu gelangen. In der bewussten Führung wird Intuition als wertvolle Ergänzung zu rationaler Analyse kultiviert.", en: "Intuition is the ability to arrive at correct assessments without conscious analysis. In conscious leadership, intuition is cultivated as a valuable complement to rational analysis.", ru: "Интуиция — способность приходить к верным оценкам без сознательного анализа. В осознанном лидерстве интуиция культивируется как ценное дополнение к рациональному анализу." }, category: "psychologie", relatedTerms: ["innere-klarheit", "bewusstsein", "entscheidungsstaerke"], relatedServices: ["coaching"] },
  { slug: "motivation", term: { de: "Motivation", en: "Motivation", ru: "Мотивация" }, definition: { de: "Intrinsische Motivation entsteht aus Sinn, Autonomie und Meisterschaft — nicht aus externen Anreizen. Bewusste Führungskräfte verstehen die Motivationsquellen ihrer Mitarbeiter und schaffen entsprechende Rahmenbedingungen.", en: "Intrinsic motivation arises from purpose, autonomy, and mastery — not from external incentives. Conscious leaders understand their employees' motivation sources and create appropriate conditions.", ru: "Внутренняя мотивация рождается из смысла, автономии и мастерства — не из внешних стимулов. Осознанные лидеры понимают источники мотивации сотрудников и создают соответствующие условия." }, category: "psychologie", relatedTerms: ["flow", "sinn", "empowerment"], relatedServices: ["corporate", "coaching"] },
  { slug: "selbstwirksamkeit", term: { de: "Selbstwirksamkeit", en: "Self-Efficacy", ru: "Самоэффективность" }, definition: { de: "Selbstwirksamkeit ist die Überzeugung, durch eigenes Handeln gewünschte Ergebnisse erzielen zu können. Sie ist ein zentraler Faktor für Resilienz, Motivation und den Mut, neue Wege zu gehen.", en: "Self-efficacy is the belief that one can achieve desired results through one's own actions. It is a central factor for resilience, motivation, and the courage to take new paths.", ru: "Самоэффективность — убеждённость в способности достигать желаемых результатов собственными действиями. Это центральный фактор стойкости, мотивации и мужества идти новыми путями." }, category: "psychologie", relatedTerms: ["resilienz", "motivation", "selbstbewusstsein"], relatedServices: ["coaching"] },
  { slug: "stress", term: { de: "Stress", en: "Stress", ru: "Стресс" }, definition: { de: "Stress ist die Reaktion auf Anforderungen, die als herausfordernd oder bedrohlich empfunden werden. Bewusster Umgang mit Stress bedeutet, die eigenen Stressmuster zu erkennen und konstruktive Bewältigungsstrategien zu entwickeln.", en: "Stress is the response to demands perceived as challenging or threatening. Conscious stress management means recognizing one's own stress patterns and developing constructive coping strategies.", ru: "Стресс — реакция на требования, воспринимаемые как вызов или угрозу. Осознанное управление стрессом означает распознавание собственных стресс-паттернов и развитие конструктивных стратегий преодоления." }, category: "psychologie", relatedTerms: ["burnout", "resilienz", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "prokrastination", term: { de: "Prokrastination", en: "Procrastination", ru: "Прокрастинация" }, definition: { de: "Prokrastination ist das chronische Aufschieben wichtiger Aufgaben trotz besseren Wissens. Hinter ihr verbergen sich oft Ängste, Perfektionismus oder mangelnde Klarheit über Prioritäten — alles Themen, die im Coaching adressiert werden.", en: "Procrastination is the chronic postponement of important tasks despite better knowledge. Behind it often lie fears, perfectionism, or lack of clarity about priorities — all topics addressed in coaching.", ru: "Прокрастинация — хроническое откладывание важных задач вопреки лучшему знанию. За ней часто скрываются страхи, перфекционизм или неясность приоритетов — всё это темы для проработки в коучинге." }, category: "psychologie", relatedTerms: ["motivation", "gewohnheitsaenderung", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "autonomie", term: { de: "Autonomie", en: "Autonomy", ru: "Автономия" }, definition: { de: "Autonomie ist die Fähigkeit zur Selbstbestimmung und eigenverantwortlichem Handeln. In der bewussten Führung bedeutet Autonomie, sowohl sich selbst als auch anderen den Raum für eigenständige Entscheidungen zu geben.", en: "Autonomy is the ability for self-determination and responsible action. In conscious leadership, autonomy means giving both oneself and others the space for independent decisions.", ru: "Автономия — способность к самоопределению и ответственному действию. В осознанном лидерстве автономия означает предоставление себе и другим пространства для самостоятельных решений." }, category: "philosophie", relatedTerms: ["verantwortung", "empowerment", "werte"], relatedServices: ["coaching"] },
  { slug: "ethik", term: { de: "Ethik", en: "Ethics", ru: "Этика" }, definition: { de: "Ethik in der Führung bedeutet, Entscheidungen nicht nur nach Effizienz, sondern nach moralischen Grundsätzen zu treffen. Ethische Führung schafft Vertrauen und langfristigen Wert für alle Beteiligten.", en: "Ethics in leadership means making decisions not only based on efficiency but on moral principles. Ethical leadership creates trust and long-term value for all stakeholders.", ru: "Этика в лидерстве означает принятие решений не только по критерию эффективности, но и на основе моральных принципов. Этичное лидерство создаёт доверие и долгосрочную ценность для всех." }, category: "philosophie", relatedTerms: ["integritaet", "verantwortung", "werte"], relatedServices: ["corporate", "keynotes"] },
  { slug: "integritaet", term: { de: "Integrität", en: "Integrity", ru: "Целостность" }, definition: { de: "Integrität bedeutet Übereinstimmung zwischen Werten, Worten und Taten. Eine integre Führungskraft handelt konsequent nach ihren Überzeugungen, auch wenn es unbequem ist — das Fundament von Vertrauen.", en: "Integrity means alignment between values, words, and actions. A leader with integrity acts consistently according to their convictions, even when it is uncomfortable — the foundation of trust.", ru: "Целостность означает соответствие между ценностями, словами и действиями. Целостный лидер действует последовательно по своим убеждениям, даже когда это неудобно — фундамент доверия." }, category: "philosophie", relatedTerms: ["authentische-fuehrung", "ethik", "werte"], relatedServices: ["coaching"] },
  { slug: "sinn", term: { de: "Sinn", en: "Purpose", ru: "Смысл" }, definition: { de: "Sinn ist der tiefere Zweck hinter dem Handeln. Sinnorientierte Führung verbindet persönliche Werte mit beruflichen Zielen und schafft eine kraftvolle Motivationsquelle jenseits von externen Anreizen.", en: "Purpose is the deeper reason behind action. Purpose-oriented leadership connects personal values with professional goals and creates a powerful source of motivation beyond external incentives.", ru: "Смысл — глубокая причина за действиями. Ориентированное на смысл лидерство соединяет личные ценности с профессиональными целями и создаёт мощный источник мотивации за пределами внешних стимулов." }, category: "philosophie", relatedTerms: ["werte", "motivation", "visionaere-fuehrung"], relatedServices: ["coaching", "keynotes"] },
  { slug: "verantwortung", term: { de: "Verantwortung", en: "Responsibility", ru: "Ответственность" }, definition: { de: "Verantwortung zu übernehmen bedeutet, die Konsequenzen des eigenen Handelns bewusst zu tragen. In der bewussten Führung ist Verantwortung kein Druck, sondern eine Quelle von Kraft und Klarheit.", en: "Taking responsibility means consciously bearing the consequences of one's own actions. In conscious leadership, responsibility is not pressure but a source of strength and clarity.", ru: "Принятие ответственности означает осознанно нести последствия собственных действий. В осознанном лидерстве ответственность — не давление, а источник силы и ясности." }, category: "philosophie", relatedTerms: ["autonomie", "ethik", "bewusste-fuehrung"], relatedServices: ["coaching", "corporate"] },
  { slug: "werte", term: { de: "Werte", en: "Values", ru: "Ценности" }, definition: { de: "Werte sind die inneren Leitplanken, die unser Denken und Handeln bestimmen. Bewusste Führung beginnt mit der Klärung der eigenen Werte und ihrer konsequenten Umsetzung im Alltag.", en: "Values are the inner guardrails that determine our thinking and action. Conscious leadership begins with clarifying one's own values and consistently implementing them in everyday life.", ru: "Ценности — внутренние ориентиры, определяющие мышление и действия. Осознанное лидерство начинается с прояснения собственных ценностей и их последовательной реализации в повседневной жизни." }, category: "philosophie", relatedTerms: ["ethik", "integritaet", "sinn"], relatedServices: ["coaching"] },
  { slug: "weisheit", term: { de: "Weisheit", en: "Wisdom", ru: "Мудрость" }, definition: { de: "Weisheit ist die Verbindung von Wissen, Erfahrung und Urteilsvermögen. Sie entsteht durch tiefe Reflexion und ermöglicht Entscheidungen, die über kurzfristigen Nutzen hinausgehen und langfristig Wert schaffen.", en: "Wisdom is the connection of knowledge, experience, and judgment. It arises through deep reflection and enables decisions that go beyond short-term benefit and create long-term value.", ru: "Мудрость — соединение знаний, опыта и рассудительности. Она рождается из глубокой рефлексии и позволяет принимать решения, выходящие за рамки краткосрочной пользы, создавая долгосрочную ценность." }, category: "philosophie", relatedTerms: ["reflexion", "sinn", "bewusstsein"], relatedServices: ["coaching", "keynotes"] },
  { slug: "tugend", term: { de: "Tugend", en: "Virtue", ru: "Добродетель" }, definition: { de: "Tugend beschreibt positive Charaktereigenschaften, die durch bewusste Praxis kultiviert werden. In der Führung sind Tugenden wie Mut, Geduld und Mitgefühl keine Schwäche, sondern Ausdruck wahrer Stärke.", en: "Virtue describes positive character traits cultivated through conscious practice. In leadership, virtues such as courage, patience, and compassion are not weakness but expressions of true strength.", ru: "Добродетель описывает положительные черты характера, культивируемые осознанной практикой. В лидерстве добродетели — мужество, терпение, сострадание — не слабость, а выражение истинной силы." }, category: "philosophie", relatedTerms: ["ethik", "integritaet", "weisheit"], relatedServices: ["coaching"] },
  { slug: "entscheidungsstaerke", term: { de: "Entscheidungsstärke", en: "Decision-Making Strength", ru: "Сила принятия решений" }, definition: { de: "Entscheidungsstärke ist die Fähigkeit, auch in komplexen und unsicheren Situationen klare, durchdachte Entscheidungen zu treffen. Sie basiert auf Klarheit, Selbstkenntnis und dem Vertrauen in die eigene Urteilskraft.", en: "Decision-making strength is the ability to make clear, well-considered decisions even in complex and uncertain situations. It is based on clarity, self-knowledge, and trust in one's own judgment.", ru: "Сила принятия решений — способность принимать ясные, продуманные решения даже в сложных и неопределённых ситуациях. Она основана на ясности, самопознании и доверии к собственному суждению." }, category: "fuehrung", relatedTerms: ["innere-klarheit", "bewusste-fuehrung", "intuition"], relatedServices: ["coaching", "corporate"] },
  { slug: "selbsterkenntnis", term: { de: "Selbsterkenntnis", en: "Self-Knowledge", ru: "Самопознание" }, definition: { de: "Selbsterkenntnis ist die tiefe Kenntnis der eigenen Werte, Stärken, Schwächen und Muster. Sie ist der erste Schritt jeder echten Transformation und bildet das Fundament bewusster Führung.", en: "Self-knowledge is the deep understanding of one's own values, strengths, weaknesses, and patterns. It is the first step of any genuine transformation and forms the foundation of conscious leadership.", ru: "Самопознание — глубокое понимание собственных ценностей, сильных и слабых сторон, паттернов. Это первый шаг любой настоящей трансформации и фундамент осознанного лидерства." }, category: "bewusstsein", relatedTerms: ["selbstbewusstsein", "bewusstseinsentwicklung", "identitaetsarbeit"], relatedServices: ["coaching", "transformation"] },
  { slug: "selbstreflexion", term: { de: "Selbstreflexion", en: "Self-Reflection", ru: "Саморефлексия" }, definition: { de: "Selbstreflexion ist die bewusste Auseinandersetzung mit den eigenen Gedanken, Gefühlen und Handlungen. Sie bildet die Grundlage für persönliches Wachstum und ermöglicht Führungskräften, blinde Flecken zu erkennen und bewusstere Entscheidungen zu treffen.", en: "Self-reflection is the conscious examination of one's own thoughts, feelings, and actions. It forms the basis for personal growth and enables leaders to recognize blind spots and make more conscious decisions.", ru: "Саморефлексия — осознанное исследование собственных мыслей, чувств и действий. Она составляет основу личного роста и позволяет руководителям распознавать слепые зоны и принимать более осознанные решения." }, category: "bewusstsein", relatedTerms: ["reflexion", "selbstbewusstsein", "journaling"], relatedServices: ["coaching", "seminare"] },
  { slug: "bewusstseinsebenen", term: { de: "Bewusstseinsebenen", en: "Levels of Consciousness", ru: "Уровни сознания" }, definition: { de: "Bewusstseinsebenen beschreiben die verschiedenen Stufen menschlicher Wahrnehmung und innerer Entwicklung. Das Verständnis dieser Ebenen ermöglicht es, gezielt an der eigenen Bewusstseinsentwicklung zu arbeiten und tiefere Einsichten zu gewinnen.", en: "Levels of consciousness describe the various stages of human perception and inner development. Understanding these levels makes it possible to purposefully work on one's own consciousness development and gain deeper insights.", ru: "Уровни сознания описывают различные ступени человеческого восприятия и внутреннего развития. Понимание этих уровней позволяет целенаправленно работать над собственным развитием сознания и обретать более глубокие инсайты." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "bewusstseinsentwicklung", "wachbewusstsein"], relatedServices: ["coaching", "seminare"] },
  { slug: "wachbewusstsein", term: { de: "Wachbewusstsein", en: "Waking Consciousness", ru: "Бодрствующее сознание" }, definition: { de: "Wachbewusstsein ist der alltägliche Zustand bewusster Wahrnehmung, in dem wir denken, planen und handeln. Die Qualität des Wachbewusstseins zu steigern bedeutet, auch im Alltag präsenter, klarer und aufmerksamer zu sein.", en: "Waking consciousness is the everyday state of aware perception in which we think, plan, and act. Increasing the quality of waking consciousness means being more present, clear, and attentive even in daily life.", ru: "Бодрствующее сознание — повседневное состояние осознанного восприятия, в котором мы думаем, планируем и действуем. Повышение качества бодрствующего сознания означает быть более присутствующим и внимательным в повседневной жизни." }, category: "bewusstsein", relatedTerms: ["bewusstseinsebenen", "achtsamkeit", "praesenz"], relatedServices: ["coaching"] },
  { slug: "unterbewusstsein", term: { de: "Unterbewusstsein", en: "Subconscious", ru: "Подсознание" }, definition: { de: "Das Unterbewusstsein speichert Erfahrungen, Überzeugungen und automatische Reaktionsmuster, die unser Verhalten maßgeblich steuern. Bewusstseinsarbeit macht diese verborgenen Programme sichtbar und ermöglicht gezielte Veränderung.", en: "The subconscious stores experiences, beliefs, and automatic reaction patterns that significantly control our behavior. Consciousness work makes these hidden programs visible and enables targeted change.", ru: "Подсознание хранит опыт, убеждения и автоматические паттерны реакций, которые существенно управляют поведением. Работа с сознанием делает эти скрытые программы видимыми и позволяет целенаправленно их менять." }, category: "bewusstsein", relatedTerms: ["bewusstsein", "bewusstseinsebenen", "mustererkennung"], relatedServices: ["coaching", "transformation"] },
  { slug: "metacognition", term: { de: "Metakognition", en: "Metacognition", ru: "Метакогниция" }, definition: { de: "Metakognition ist das Denken über das eigene Denken — die Fähigkeit, die eigenen Denkprozesse zu beobachten und zu steuern. Sie ist eine Schlüsselkompetenz für bewusste Führung und fundierte Entscheidungsfindung.", en: "Metacognition is thinking about one's own thinking — the ability to observe and direct one's own thought processes. It is a key competency for conscious leadership and well-founded decision-making.", ru: "Метакогниция — мышление о собственном мышлении, способность наблюдать и направлять свои мыслительные процессы. Это ключевая компетенция для осознанного лидерства и обоснованного принятия решений." }, category: "bewusstsein", relatedTerms: ["selbstreflexion", "bewusstsein", "innere-klarheit"], relatedServices: ["coaching"] },
  { slug: "perspektivenwechsel", term: { de: "Perspektivenwechsel", en: "Perspective Shift", ru: "Смена перспективы" }, definition: { de: "Perspektivenwechsel ist die bewusste Fähigkeit, eine Situation aus verschiedenen Blickwinkeln zu betrachten. In der Führung ermöglicht er tieferes Verständnis, kreativere Lösungen und empathischere Kommunikation mit Mitarbeitern und Stakeholdern.", en: "Perspective shift is the conscious ability to view a situation from different angles. In leadership, it enables deeper understanding, more creative solutions, and more empathetic communication with employees and stakeholders.", ru: "Смена перспективы — осознанная способность рассматривать ситуацию с разных точек зрения. В лидерстве она обеспечивает более глубокое понимание, креативные решения и эмпатичную коммуникацию." }, category: "bewusstsein", relatedTerms: ["emotionale-intelligenz", "metacognition", "selbstreflexion"], relatedServices: ["coaching", "corporate"] },
  { slug: "aufmerksamkeit", term: { de: "Aufmerksamkeit", en: "Attention", ru: "Внимание" }, definition: { de: "Aufmerksamkeit ist die gezielte Ausrichtung des Geistes auf bestimmte Inhalte oder Erfahrungen. In der bewussten Führung ist die Steuerung der eigenen Aufmerksamkeit die wichtigste Ressource für Klarheit und Wirksamkeit.", en: "Attention is the deliberate focusing of the mind on specific content or experiences. In conscious leadership, directing one's own attention is the most important resource for clarity and effectiveness.", ru: "Внимание — целенаправленная фокусировка ума на определённых содержаниях или переживаниях. В осознанном лидерстве управление собственным вниманием — важнейший ресурс для ясности и эффективности." }, category: "bewusstsein", relatedTerms: ["achtsamkeit", "konzentration", "praesenz"], relatedServices: ["coaching", "seminare"] },
  { slug: "konzentration", term: { de: "Konzentration", en: "Concentration", ru: "Концентрация" }, definition: { de: "Konzentration ist die Fähigkeit, die Aufmerksamkeit über einen längeren Zeitraum auf eine Aufgabe zu richten. In einer Welt ständiger Ablenkungen ist sie eine entscheidende Führungskompetenz, die durch bewusste Praxis gestärkt werden kann.", en: "Concentration is the ability to direct attention on a task over an extended period. In a world of constant distractions, it is a crucial leadership competency that can be strengthened through conscious practice.", ru: "Концентрация — способность направлять внимание на задачу в течение длительного времени. В мире постоянных отвлечений это решающая лидерская компетенция, укрепляемая осознанной практикой." }, category: "bewusstsein", relatedTerms: ["aufmerksamkeit", "flow", "meditation"], relatedServices: ["coaching"] },
  { slug: "transformationale-fuehrung", term: { de: "Transformationale Führung", en: "Transformational Leadership", ru: "Трансформационное лидерство" }, definition: { de: "Transformationale Führung inspiriert Mitarbeiter, über ihre eigenen Interessen hinauszugehen und gemeinsame Visionen zu verfolgen. Sie setzt auf intrinsische Motivation, intellektuelle Stimulation und individuelle Wertschätzung als Treiber nachhaltiger Veränderung.", en: "Transformational leadership inspires employees to go beyond their own interests and pursue shared visions. It relies on intrinsic motivation, intellectual stimulation, and individual appreciation as drivers of sustainable change.", ru: "Трансформационное лидерство вдохновляет сотрудников выходить за рамки личных интересов и следовать общему видению. Оно опирается на внутреннюю мотивацию, интеллектуальную стимуляцию и индивидуальное признание как движущие силы устойчивых изменений." }, category: "fuehrung", relatedTerms: ["visionaere-fuehrung", "bewusste-fuehrung", "empowerment"], relatedServices: ["corporate", "keynotes"] },
  { slug: "agile-fuehrung", term: { de: "Agile Führung", en: "Agile Leadership", ru: "Гибкое лидерство" }, definition: { de: "Agile Führung verbindet schnelle Anpassungsfähigkeit mit klarer strategischer Ausrichtung. Agile Führungskräfte schaffen Rahmenbedingungen für Selbstorganisation und reagieren flexibel auf Veränderungen, ohne die langfristige Vision aus den Augen zu verlieren.", en: "Agile leadership combines rapid adaptability with clear strategic direction. Agile leaders create conditions for self-organization and respond flexibly to changes without losing sight of the long-term vision.", ru: "Гибкое лидерство сочетает быструю адаптивность с чёткой стратегической направленностью. Гибкие лидеры создают условия для самоорганизации и гибко реагируют на изменения, не теряя из виду долгосрочное видение." }, category: "fuehrung", relatedTerms: ["agilitat", "empowerment", "situative-fuehrung"], relatedServices: ["corporate"] },
  { slug: "coachende-fuehrung", term: { de: "Coachende Führung", en: "Coaching Leadership", ru: "Коучинговое лидерство" }, definition: { de: "Coachende Führung nutzt Coaching-Methoden im Führungsalltag, um Mitarbeiter in ihrer Entwicklung zu begleiten. Statt Anweisungen zu geben, stellt die coachende Führungskraft Fragen und fördert eigenständiges Denken und Handeln.", en: "Coaching leadership uses coaching methods in everyday leadership to support employees in their development. Instead of giving instructions, the coaching leader asks questions and promotes independent thinking and action.", ru: "Коучинговое лидерство использует методы коучинга в повседневном руководстве для поддержки развития сотрудников. Вместо инструкций коучинговый лидер задаёт вопросы и развивает самостоятельное мышление и действие." }, category: "fuehrung", relatedTerms: ["servant-leadership", "empowerment", "feedback"], relatedServices: ["corporate", "coaching"] },
  { slug: "fehlerkultur", term: { de: "Fehlerkultur", en: "Error Culture", ru: "Культура ошибок" }, definition: { de: "Fehlerkultur beschreibt den Umgang einer Organisation mit Fehlern und Misserfolgen. Eine konstruktive Fehlerkultur betrachtet Fehler als Lernchancen und fördert Offenheit, Innovation und psychologische Sicherheit im Team.", en: "Error culture describes how an organization deals with mistakes and failures. A constructive error culture views mistakes as learning opportunities and promotes openness, innovation, and psychological safety within the team.", ru: "Культура ошибок описывает отношение организации к ошибкам и неудачам. Конструктивная культура ошибок рассматривает их как возможности для обучения и способствует открытости, инновациям и психологической безопасности." }, category: "fuehrung", relatedTerms: ["psychologische-sicherheit", "vertrauenskultur", "innovation"], relatedServices: ["corporate"] },
  { slug: "feedback-kultur", term: { de: "Feedback-Kultur", en: "Feedback Culture", ru: "Культура обратной связи" }, definition: { de: "Feedback-Kultur bezeichnet ein Umfeld, in dem offenes, konstruktives Feedback selbstverständlich ist. Sie erfordert Vertrauen, Mut und klare Kommunikationsregeln und ist ein wesentlicher Baustein bewusster Organisationsentwicklung.", en: "Feedback culture refers to an environment where open, constructive feedback is natural. It requires trust, courage, and clear communication rules and is an essential building block of conscious organizational development.", ru: "Культура обратной связи означает среду, где открытая, конструктивная обратная связь является нормой. Она требует доверия, мужества и чётких правил коммуникации и является важным элементом осознанного развития организации." }, category: "fuehrung", relatedTerms: ["feedback", "vertrauenskultur", "bewusste-fuehrung"], relatedServices: ["corporate"] },
  { slug: "vertrauenskultur", term: { de: "Vertrauenskultur", en: "Trust Culture", ru: "Культура доверия" }, definition: { de: "Vertrauenskultur ist das Fundament leistungsfähiger Organisationen. Sie entsteht durch konsistentes Handeln, Transparenz und die Bereitschaft von Führungskräften, Kontrolle abzugeben und echte Autonomie zu ermöglichen.", en: "Trust culture is the foundation of high-performing organizations. It emerges through consistent action, transparency, and the willingness of leaders to relinquish control and enable genuine autonomy.", ru: "Культура доверия — фундамент эффективных организаций. Она возникает через последовательные действия, прозрачность и готовность руководителей делегировать контроль и обеспечивать подлинную автономию." }, category: "fuehrung", relatedTerms: ["feedback-kultur", "fehlerkultur", "empowerment"], relatedServices: ["corporate", "coaching"] },
  { slug: "entscheidungsmatrix", term: { de: "Entscheidungsmatrix", en: "Decision Matrix", ru: "Матрица решений" }, definition: { de: "Eine Entscheidungsmatrix ist ein strukturiertes Werkzeug zur systematischen Bewertung von Alternativen anhand gewichteter Kriterien. Sie verbindet rationale Analyse mit bewusster Reflexion und hilft Führungskräften, komplexe Entscheidungen transparent zu treffen.", en: "A decision matrix is a structured tool for systematically evaluating alternatives based on weighted criteria. It combines rational analysis with conscious reflection and helps leaders make complex decisions transparently.", ru: "Матрица решений — структурированный инструмент для систематической оценки альтернатив по взвешенным критериям. Она сочетает рациональный анализ с осознанной рефлексией и помогает руководителям принимать сложные решения прозрачно." }, category: "fuehrung", relatedTerms: ["entscheidungsstaerke", "swot-analyse", "szenarioplanung"], relatedServices: ["corporate", "coaching"] },
  { slug: "konfliktmanagement", term: { de: "Konfliktmanagement", en: "Conflict Management", ru: "Управление конфликтами" }, definition: { de: "Konfliktmanagement umfasst die Fähigkeit, Konflikte frühzeitig zu erkennen, konstruktiv zu adressieren und als Entwicklungschance zu nutzen. Bewusste Führungskräfte sehen Konflikte nicht als Störung, sondern als Quelle für Innovation und Wachstum.", en: "Conflict management encompasses the ability to recognize conflicts early, address them constructively, and use them as development opportunities. Conscious leaders view conflicts not as disruptions but as sources of innovation and growth.", ru: "Управление конфликтами охватывает способность распознавать конфликты на ранней стадии, конструктивно решать их и использовать как возможность для развития. Осознанные лидеры видят в конфликтах не помеху, а источник инноваций и роста." }, category: "fuehrung", relatedTerms: ["feedback-kultur", "fehlerkultur", "psychologische-sicherheit"], relatedServices: ["corporate", "coaching"] },
  { slug: "life-coaching", term: { de: "Life Coaching", en: "Life Coaching", ru: "Лайф-коучинг" }, definition: { de: "Life Coaching begleitet Menschen bei der Gestaltung eines erfüllten Lebens in all seinen Facetten. Es adressiert persönliche Ziele, Beziehungen, Sinnfindung und die Balance zwischen verschiedenen Lebensbereichen mit dem Ziel ganzheitlicher Klarheit.", en: "Life coaching supports people in creating a fulfilling life in all its facets. It addresses personal goals, relationships, finding meaning, and the balance between different life areas with the goal of holistic clarity.", ru: "Лайф-коучинг сопровождает людей в создании полноценной жизни во всех её аспектах. Он работает с личными целями, отношениями, поиском смысла и балансом между сферами жизни для достижения целостной ясности." }, category: "coaching", relatedTerms: ["einzelcoaching", "executive-coaching", "mentoring"], relatedServices: ["coaching"] },
  { slug: "business-coaching", term: { de: "Business Coaching", en: "Business Coaching", ru: "Бизнес-коучинг" }, definition: { de: "Business Coaching fokussiert auf berufliche Herausforderungen wie Strategieentwicklung, unternehmerisches Wachstum und professionelle Wirksamkeit. Es verbindet Geschäftskompetenz mit persönlicher Entwicklung für nachhaltigen beruflichen Erfolg.", en: "Business coaching focuses on professional challenges such as strategy development, entrepreneurial growth, and professional effectiveness. It combines business competence with personal development for sustainable professional success.", ru: "Бизнес-коучинг фокусируется на профессиональных вызовах: разработке стратегии, предпринимательском росте и профессиональной эффективности. Он сочетает бизнес-компетенции с личным развитием для устойчивого профессионального успеха." }, category: "coaching", relatedTerms: ["executive-coaching", "karrierecoaching", "sparring"], relatedServices: ["coaching", "corporate"] },
  { slug: "karrierecoaching", term: { de: "Karrierecoaching", en: "Career Coaching", ru: "Карьерный коучинг" }, definition: { de: "Karrierecoaching unterstützt bei beruflicher Orientierung, Karriereplanung und dem Erreichen professioneller Ziele. Es hilft, die eigenen Talente und Werte mit beruflichen Möglichkeiten in Einklang zu bringen.", en: "Career coaching supports professional orientation, career planning, and achieving professional goals. It helps align one's own talents and values with professional opportunities.", ru: "Карьерный коучинг помогает в профессиональной ориентации, планировании карьеры и достижении профессиональных целей. Он помогает согласовать собственные таланты и ценности с профессиональными возможностями." }, category: "coaching", relatedTerms: ["business-coaching", "neuausrichtung", "einzelcoaching"], relatedServices: ["coaching"] },
  { slug: "transition-coaching", term: { de: "Transition Coaching", en: "Transition Coaching", ru: "Коучинг переходного периода" }, definition: { de: "Transition Coaching begleitet Menschen durch berufliche und persönliche Übergangsphasen wie Beförderungen, Jobwechsel oder Neuorientierung. Es sorgt dafür, dass Übergänge bewusst gestaltet werden statt reaktiv zu geschehen.", en: "Transition coaching guides people through professional and personal transition phases such as promotions, job changes, or reorientation. It ensures that transitions are consciously shaped rather than happening reactively.", ru: "Коучинг переходного периода сопровождает людей через профессиональные и личные переходные фазы: повышения, смену работы или переориентацию. Он обеспечивает осознанное формирование переходов вместо реактивного реагирования." }, category: "coaching", relatedTerms: ["neuausrichtung", "karrierecoaching", "veraenderungsprozess"], relatedServices: ["coaching"] },
  { slug: "performance-coaching", term: { de: "Performance Coaching", en: "Performance Coaching", ru: "Коучинг эффективности" }, definition: { de: "Performance Coaching zielt auf die Steigerung beruflicher Leistungsfähigkeit bei gleichzeitiger Erhaltung von Wohlbefinden und Lebensqualität. Es identifiziert Leistungsblockaden und entwickelt nachhaltige Strategien für Spitzenleistung ohne Burnout-Risiko.", en: "Performance coaching aims at increasing professional performance while maintaining well-being and quality of life. It identifies performance blocks and develops sustainable strategies for peak performance without burnout risk.", ru: "Коучинг эффективности направлен на повышение профессиональной результативности при сохранении благополучия и качества жизни. Он выявляет блоки производительности и разрабатывает устойчивые стратегии пиковой эффективности без риска выгорания." }, category: "coaching", relatedTerms: ["executive-coaching", "selbstoptimierung", "flow"], relatedServices: ["coaching", "corporate"] },
  { slug: "onboarding-coaching", term: { de: "Onboarding Coaching", en: "Onboarding Coaching", ru: "Коучинг адаптации" }, definition: { de: "Onboarding Coaching begleitet Führungskräfte in den ersten 90 bis 180 Tagen einer neuen Position. Es beschleunigt die Integration, baut tragfähige Beziehungen auf und verhindert typische Anfangsfehler in Führungsrollen.", en: "Onboarding coaching accompanies leaders during the first 90 to 180 days of a new position. It accelerates integration, builds sustainable relationships, and prevents typical early mistakes in leadership roles.", ru: "Коучинг адаптации сопровождает руководителей в первые 90-180 дней на новой позиции. Он ускоряет интеграцию, выстраивает устойчивые отношения и предотвращает типичные ошибки начального периода в руководящих ролях." }, category: "coaching", relatedTerms: ["transition-coaching", "executive-coaching", "einzelcoaching"], relatedServices: ["coaching", "corporate"] },
  { slug: "konfliktcoaching", term: { de: "Konfliktcoaching", en: "Conflict Coaching", ru: "Конфликтный коучинг" }, definition: { de: "Konfliktcoaching hilft Einzelpersonen und Teams, Konflikte konstruktiv zu verstehen und zu lösen. Es stärkt die Fähigkeit, schwierige Gespräche zu führen und aus Konfliktsituationen gestärkt hervorzugehen.", en: "Conflict coaching helps individuals and teams understand and resolve conflicts constructively. It strengthens the ability to conduct difficult conversations and emerge stronger from conflict situations.", ru: "Конфликтный коучинг помогает людям и командам конструктивно понимать и разрешать конфликты. Он укрепляет способность вести сложные разговоры и выходить из конфликтных ситуаций сильнее." }, category: "coaching", relatedTerms: ["konfliktmanagement", "team-coaching", "systemisches-coaching"], relatedServices: ["coaching", "corporate"] },
  { slug: "integrationscoaching", term: { de: "Integrationscoaching", en: "Integration Coaching", ru: "Интеграционный коучинг" }, definition: { de: "Integrationscoaching unterstützt die nachhaltige Verankerung von Erkenntnissen und Veränderungen im Alltag. Es sorgt dafür, dass Einsichten aus Seminaren, Retreats oder intensiven Coaching-Phasen dauerhaft wirksam werden.", en: "Integration coaching supports the sustainable anchoring of insights and changes in everyday life. It ensures that insights from seminars, retreats, or intensive coaching phases become permanently effective.", ru: "Интеграционный коучинг помогает устойчиво закрепить инсайты и изменения в повседневной жизни. Он обеспечивает, что открытия из семинаров, ретритов или интенсивных фаз коучинга становятся долговременно действенными." }, category: "coaching", relatedTerms: ["einzelcoaching", "systemisches-coaching", "veraenderungsprozess"], relatedServices: ["coaching", "seminare"] },
  { slug: "paradigmenwechsel", term: { de: "Paradigmenwechsel", en: "Paradigm Shift", ru: "Смена парадигмы" }, definition: { de: "Ein Paradigmenwechsel ist eine grundlegende Veränderung der Denk- und Wahrnehmungsweise. Er geschieht, wenn bisherige Annahmen und Modelle nicht mehr ausreichen und eine vollkommen neue Sichtweise entsteht, die alles verändert.", en: "A paradigm shift is a fundamental change in thinking and perception. It occurs when previous assumptions and models are no longer sufficient and a completely new perspective emerges that changes everything.", ru: "Смена парадигмы — фундаментальное изменение образа мышления и восприятия. Она происходит, когда прежние допущения и модели перестают работать и возникает совершенно новая точка зрения, меняющая всё." }, category: "transformation", relatedTerms: ["persoenliche-transformation", "durchbruch", "bewusstseinsentwicklung"], relatedServices: ["coaching", "transformation"] },
  { slug: "durchbruch", term: { de: "Durchbruch", en: "Breakthrough", ru: "Прорыв" }, definition: { de: "Ein Durchbruch ist ein Moment der plötzlichen Klarheit, in dem sich langanhaltende Blockaden lösen und neue Möglichkeiten sichtbar werden. In der Coaching-Arbeit entstehen Durchbrüche durch tiefe Bewusstseinsarbeit und den Mut zur ehrlichen Selbstbegegnung.", en: "A breakthrough is a moment of sudden clarity when long-standing blockages dissolve and new possibilities become visible. In coaching work, breakthroughs emerge through deep consciousness work and the courage for honest self-encounter.", ru: "Прорыв — момент внезапной ясности, когда давние блокировки растворяются и открываются новые возможности. В коучинге прорывы возникают через глубокую работу с сознанием и мужество для честной встречи с собой." }, category: "transformation", relatedTerms: ["paradigmenwechsel", "persoenliche-transformation", "innere-klarheit"], relatedServices: ["coaching", "seminare"] },
  { slug: "komfortzone", term: { de: "Komfortzone", en: "Comfort Zone", ru: "Зона комфорта" }, definition: { de: "Die Komfortzone ist der Bereich, in dem Handlungen und Situationen vertraut und sicher erscheinen. Echtes Wachstum beginnt an ihrem Rand — durch bewusste, dosierte Expansion entsteht nachhaltige Entwicklung ohne Überforderung.", en: "The comfort zone is the area where actions and situations feel familiar and safe. Real growth begins at its edge — through conscious, measured expansion, sustainable development emerges without overwhelm.", ru: "Зона комфорта — область, где действия и ситуации ощущаются привычными и безопасными. Настоящий рост начинается на её границе — через осознанное, дозированное расширение возникает устойчивое развитие без перегрузки." }, category: "transformation", relatedTerms: ["wachstum", "resilienz", "durchbruch"], relatedServices: ["coaching", "seminare"] },
  { slug: "loslassen", term: { de: "Loslassen", en: "Letting Go", ru: "Отпускание" }, definition: { de: "Loslassen ist die bewusste Entscheidung, alte Überzeugungen, Gewohnheiten oder Identitäten freizugeben, die nicht mehr dienlich sind. Es ist kein Verlust, sondern eine Befreiung, die Raum für Neues schafft und tiefe innere Freiheit ermöglicht.", en: "Letting go is the conscious decision to release old beliefs, habits, or identities that no longer serve. It is not a loss but a liberation that creates space for the new and enables deep inner freedom.", ru: "Отпускание — осознанное решение освободиться от старых убеждений, привычек или идентичностей, которые больше не служат. Это не потеря, а освобождение, создающее пространство для нового и глубокую внутреннюю свободу." }, category: "transformation", relatedTerms: ["akzeptanz", "persoenliche-transformation", "identitaetsarbeit"], relatedServices: ["coaching", "transformation"] },
  { slug: "akzeptanz", term: { de: "Akzeptanz", en: "Acceptance", ru: "Принятие" }, definition: { de: "Akzeptanz bedeutet, die Realität so anzunehmen, wie sie ist, bevor man sie zu verändern sucht. Sie ist kein Aufgeben, sondern die kraftvolle Grundlage für bewusste Veränderung und inneren Frieden in herausfordernden Situationen.", en: "Acceptance means embracing reality as it is before seeking to change it. It is not giving up but the powerful foundation for conscious change and inner peace in challenging situations.", ru: "Принятие означает признание реальности такой, какая она есть, прежде чем пытаться её изменить. Это не сдача, а мощная основа для осознанных изменений и внутреннего покоя в сложных ситуациях." }, category: "transformation", relatedTerms: ["loslassen", "resilienz", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "integration", term: { de: "Integration", en: "Integration", ru: "Интеграция" }, definition: { de: "Integration bezeichnet den Prozess, neue Erkenntnisse, Erfahrungen und Verhaltensweisen in das alltägliche Leben einzubinden. Ohne Integration bleiben Einsichten theoretisch — mit ihr werden sie zu gelebter Transformation.", en: "Integration refers to the process of incorporating new insights, experiences, and behaviors into everyday life. Without integration, insights remain theoretical — with it, they become lived transformation.", ru: "Интеграция — процесс встраивания новых знаний, опыта и поведения в повседневную жизнь. Без интеграции инсайты остаются теоретическими — с ней они становятся прожитой трансформацией." }, category: "transformation", relatedTerms: ["veraenderungsprozess", "integrationscoaching", "gewohnheitsaenderung"], relatedServices: ["coaching", "seminare"] },
  { slug: "mustererkennung", term: { de: "Mustererkennung", en: "Pattern Recognition", ru: "Распознавание паттернов" }, definition: { de: "Mustererkennung ist die Fähigkeit, wiederkehrende Denk-, Verhaltens- und Beziehungsmuster zu identifizieren. In der Coaching-Arbeit ist sie der Schlüssel zur Veränderung, denn nur erkannte Muster können bewusst transformiert werden.", en: "Pattern recognition is the ability to identify recurring thinking, behavioral, and relational patterns. In coaching work, it is the key to change, because only recognized patterns can be consciously transformed.", ru: "Распознавание паттернов — способность выявлять повторяющиеся модели мышления, поведения и отношений. В коучинге это ключ к изменениям, ведь только осознанные паттерны могут быть трансформированы." }, category: "transformation", relatedTerms: ["selbstreflexion", "metacognition", "unterbewusstsein"], relatedServices: ["coaching"] },
  { slug: "selbstregulation", term: { de: "Selbstregulation", en: "Self-Regulation", ru: "Саморегуляция" }, definition: { de: "Selbstregulation ist die Fähigkeit, die eigenen Emotionen, Impulse und Reaktionen bewusst zu steuern. Sie ermöglicht besonnenes Handeln unter Druck und ist eine Kernkompetenz für effektive Führung in komplexen Situationen.", en: "Self-regulation is the ability to consciously manage one's own emotions, impulses, and reactions. It enables composed action under pressure and is a core competency for effective leadership in complex situations.", ru: "Саморегуляция — способность осознанно управлять собственными эмоциями, импульсами и реакциями. Она обеспечивает взвешенное действие под давлением и является ключевой компетенцией эффективного лидерства в сложных ситуациях." }, category: "transformation", relatedTerms: ["emotionale-intelligenz", "resilienz", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "change-management", term: { de: "Change Management", en: "Change Management", ru: "Управление изменениями" }, definition: { de: "Change Management ist die systematische Gestaltung von Veränderungsprozessen in Organisationen. Nachhaltiges Change Management beginnt bei den Menschen und ihrer Bewusstheit, nicht nur bei Strukturen und Prozessen.", en: "Change management is the systematic design of change processes in organizations. Sustainable change management begins with people and their awareness, not just structures and processes.", ru: "Управление изменениями — систематическое формирование процессов перемен в организациях. Устойчивое управление изменениями начинается с людей и их осознанности, а не только со структур и процессов." }, category: "business", relatedTerms: ["organisationsentwicklung", "veraenderungsprozess", "agilitat"], relatedServices: ["corporate"] },
  { slug: "digitale-transformation", term: { de: "Digitale Transformation", en: "Digital Transformation", ru: "Цифровая трансформация" }, definition: { de: "Digitale Transformation ist weit mehr als Technologieeinführung — sie erfordert einen grundlegenden Wandel in Denkweise, Kultur und Führung. Bewusste Führungskräfte gestalten diesen Wandel menschenzentriert und nachhaltig.", en: "Digital transformation is far more than technology adoption — it requires a fundamental shift in mindset, culture, and leadership. Conscious leaders shape this change in a human-centered and sustainable way.", ru: "Цифровая трансформация — гораздо больше, чем внедрение технологий. Она требует фундаментального сдвига в мышлении, культуре и лидерстве. Осознанные руководители формируют этот переход человекоцентрично и устойчиво." }, category: "business", relatedTerms: ["change-management", "agilitat", "innovation"], relatedServices: ["corporate", "keynotes"] },
  { slug: "diversity", term: { de: "Diversity", en: "Diversity", ru: "Разнообразие" }, definition: { de: "Diversity umfasst die Wertschätzung und bewusste Nutzung von Vielfalt in Organisationen — sei es in Bezug auf Herkunft, Perspektiven, Erfahrungen oder Denkweisen. Echte Diversity entsteht durch eine Kultur der Offenheit und Inklusion.", en: "Diversity encompasses the appreciation and conscious use of variety in organizations — whether in terms of background, perspectives, experiences, or ways of thinking. True diversity emerges through a culture of openness and inclusion.", ru: "Разнообразие охватывает признание и осознанное использование многообразия в организациях — будь то происхождение, перспективы, опыт или образ мышления. Настоящее разнообразие возникает через культуру открытости и инклюзии." }, category: "business", relatedTerms: ["unternehmenskultur", "innovation", "psychologische-sicherheit"], relatedServices: ["corporate"] },
  { slug: "stakeholder-management", term: { de: "Stakeholder Management", en: "Stakeholder Management", ru: "Управление стейкхолдерами" }, definition: { de: "Stakeholder Management ist die bewusste Gestaltung von Beziehungen zu allen relevanten Interessengruppen. Es erfordert Empathie, strategisches Denken und die Fähigkeit, unterschiedliche Interessen zu einem gemeinsamen Weg zu vereinen.", en: "Stakeholder management is the conscious design of relationships with all relevant interest groups. It requires empathy, strategic thinking, and the ability to unite different interests into a common path.", ru: "Управление стейкхолдерами — осознанное выстраивание отношений со всеми заинтересованными группами. Оно требует эмпатии, стратегического мышления и способности объединять различные интересы в общий путь." }, category: "business", relatedTerms: ["bewusste-fuehrung", "strategieentwicklung", "nachhaltigkeit"], relatedServices: ["corporate"] },
  { slug: "strategieentwicklung", term: { de: "Strategieentwicklung", en: "Strategy Development", ru: "Разработка стратегии" }, definition: { de: "Strategieentwicklung ist der Prozess, eine klare Richtung und einen Weg dorthin zu definieren. Bewusste Strategieentwicklung verbindet analytisches Denken mit intuitiver Weisheit und schafft Orientierung in unsicheren Zeiten.", en: "Strategy development is the process of defining a clear direction and a path to get there. Conscious strategy development combines analytical thinking with intuitive wisdom and creates orientation in uncertain times.", ru: "Разработка стратегии — процесс определения ясного направления и пути к нему. Осознанная разработка стратегии сочетает аналитическое мышление с интуитивной мудростью и создаёт ориентиры в неопределённые времена." }, category: "business", relatedTerms: ["stakeholder-management", "szenarioplanung", "visionaere-fuehrung"], relatedServices: ["corporate", "coaching"] },
  { slug: "talentmanagement", term: { de: "Talentmanagement", en: "Talent Management", ru: "Управление талантами" }, definition: { de: "Talentmanagement umfasst die Gewinnung, Entwicklung und Bindung von Schlüsselpersonen. Bewusste Führungskräfte erkennen die einzigartigen Stärken ihrer Mitarbeiter und schaffen Bedingungen, in denen Talente aufblühen können.", en: "Talent management encompasses the acquisition, development, and retention of key people. Conscious leaders recognize the unique strengths of their employees and create conditions in which talents can flourish.", ru: "Управление талантами охватывает привлечение, развитие и удержание ключевых специалистов. Осознанные руководители распознают уникальные сильные стороны сотрудников и создают условия для раскрытия талантов." }, category: "business", relatedTerms: ["employer-branding", "empowerment", "organisationsentwicklung"], relatedServices: ["corporate"] },
  { slug: "wissensmanagement", term: { de: "Wissensmanagement", en: "Knowledge Management", ru: "Управление знаниями" }, definition: { de: "Wissensmanagement ist der systematische Umgang mit dem Wissen einer Organisation. Es sichert wertvolles Erfahrungswissen, fördert den Wissensaustausch und schafft die Grundlage für kontinuierliches organisationales Lernen.", en: "Knowledge management is the systematic handling of an organization's knowledge. It secures valuable experiential knowledge, promotes knowledge sharing, and creates the foundation for continuous organizational learning.", ru: "Управление знаниями — систематическая работа со знаниями организации. Оно сохраняет ценный опыт, способствует обмену знаниями и создаёт основу для непрерывного организационного обучения." }, category: "business", relatedTerms: ["organisationsentwicklung", "innovation", "nachhaltigkeit"], relatedServices: ["corporate"] },
  { slug: "purpose-driven-business", term: { de: "Purpose-driven Business", en: "Purpose-driven Business", ru: "Бизнес, движимый целью" }, definition: { de: "Purpose-driven Business stellt einen höheren Zweck ins Zentrum unternehmerischen Handelns. Unternehmen mit klarem Purpose ziehen engagierte Talente an, schaffen loyale Kunden und erzielen langfristig bessere Ergebnisse als rein profitorientierte Organisationen.", en: "Purpose-driven business places a higher purpose at the center of entrepreneurial action. Companies with clear purpose attract engaged talent, create loyal customers, and achieve better results long-term than purely profit-oriented organizations.", ru: "Бизнес, движимый целью, ставит высшую цель в центр предпринимательской деятельности. Компании с ясной целью привлекают увлечённых специалистов, создают лояльных клиентов и достигают лучших результатов, чем чисто прибыльно ориентированные организации." }, category: "business", relatedTerms: ["sinn", "nachhaltigkeit", "unternehmenskultur"], relatedServices: ["corporate", "keynotes"] },
  { slug: "atemarbeit", term: { de: "Atemarbeit", en: "Breathwork", ru: "Дыхательные практики" }, definition: { de: "Atemarbeit nutzt gezielte Atemtechniken, um emotionale Blockaden zu lösen, Stress abzubauen und tiefere Bewusstseinszustände zu erreichen. Als eine der ältesten Heilmethoden verbindet sie Körper und Geist auf direkte Weise.", en: "Breathwork uses targeted breathing techniques to release emotional blockages, reduce stress, and access deeper states of consciousness. As one of the oldest healing methods, it directly connects body and mind.", ru: "Дыхательные практики используют целенаправленные техники дыхания для освобождения от эмоциональных блоков, снижения стресса и достижения глубоких состояний сознания. Как один из древнейших методов исцеления, они напрямую связывают тело и разум." }, category: "methodik", relatedTerms: ["meditation", "koerperarbeit", "achtsamkeit"], relatedServices: ["seminare"] },
  { slug: "koerperarbeit", term: { de: "Körperarbeit", en: "Bodywork", ru: "Телесные практики" }, definition: { de: "Körperarbeit integriert den Körper als Informationsquelle und Transformationsinstrument in den Coaching-Prozess. Der Körper speichert Erfahrungen und Emotionen, die durch bewusste Arbeit zugänglich und transformierbar werden.", en: "Bodywork integrates the body as a source of information and instrument of transformation in the coaching process. The body stores experiences and emotions that become accessible and transformable through conscious work.", ru: "Телесные практики интегрируют тело как источник информации и инструмент трансформации в коучинг-процесс. Тело хранит опыт и эмоции, которые через осознанную работу становятся доступными и трансформируемыми." }, category: "methodik", relatedTerms: ["atemarbeit", "meditation", "achtsamkeit"], relatedServices: ["seminare"] },
  { slug: "systemaufstellung", term: { de: "Systemaufstellung", en: "Systemic Constellation", ru: "Системная расстановка" }, definition: { de: "Systemaufstellungen machen verborgene Dynamiken in Beziehungssystemen sichtbar. Durch die räumliche Darstellung von Beziehungen entstehen überraschende Einsichten und Lösungen, die durch rein verbale Methoden schwer zugänglich wären.", en: "Systemic constellations make hidden dynamics in relationship systems visible. Through the spatial representation of relationships, surprising insights and solutions emerge that would be difficult to access through purely verbal methods.", ru: "Системные расстановки делают видимыми скрытые динамики в системах отношений. Через пространственное представление отношений возникают неожиданные инсайты и решения, труднодоступные чисто вербальными методами." }, category: "methodik", relatedTerms: ["systemisches-coaching", "facilitation", "team-coaching"], relatedServices: ["seminare", "coaching"] },
  { slug: "design-thinking", term: { de: "Design Thinking", en: "Design Thinking", ru: "Дизайн-мышление" }, definition: { de: "Design Thinking ist eine kreative Problemlösungsmethode, die den Menschen in den Mittelpunkt stellt. Durch iteratives Prototyping und Nutzerfeedback entstehen innovative Lösungen, die tatsächliche Bedürfnisse adressieren.", en: "Design thinking is a creative problem-solving method that puts people at the center. Through iterative prototyping and user feedback, innovative solutions emerge that address actual needs.", ru: "Дизайн-мышление — креативный метод решения проблем, ставящий человека в центр. Через итеративное прототипирование и обратную связь пользователей рождаются инновационные решения, отвечающие реальным потребностям." }, category: "methodik", relatedTerms: ["innovation", "workshop", "agilitat"], relatedServices: ["corporate"] },
  { slug: "okr", term: { de: "OKR", en: "OKR", ru: "OKR" }, definition: { de: "OKR (Objectives and Key Results) ist ein Rahmenwerk zur Zielsetzung und Erfolgsmessung, das Transparenz und Ausrichtung in Organisationen schafft. In Verbindung mit bewusster Führung wird OKR zum kraftvollen Instrument für sinnorientierte Ergebnisse.", en: "OKR (Objectives and Key Results) is a framework for goal setting and measuring success that creates transparency and alignment in organizations. Combined with conscious leadership, OKR becomes a powerful instrument for purpose-oriented results.", ru: "OKR (Objectives and Key Results) — система постановки целей и измерения успеха, создающая прозрачность и согласованность в организациях. В сочетании с осознанным лидерством OKR становится мощным инструментом для достижения осмысленных результатов." }, category: "methodik", relatedTerms: ["strategieentwicklung", "assessment", "agilitat"], relatedServices: ["corporate"] },
  { slug: "swot-analyse", term: { de: "SWOT-Analyse", en: "SWOT Analysis", ru: "SWOT-анализ" }, definition: { de: "Die SWOT-Analyse ist ein strategisches Werkzeug zur Bewertung von Stärken, Schwächen, Chancen und Risiken. In der bewussten Führung wird sie durch Selbstkenntnis und intuitive Einsichten ergänzt, um ein ganzheitliches Bild zu erhalten.", en: "SWOT analysis is a strategic tool for evaluating strengths, weaknesses, opportunities, and threats. In conscious leadership, it is complemented by self-knowledge and intuitive insights to obtain a holistic picture.", ru: "SWOT-анализ — стратегический инструмент оценки сильных и слабых сторон, возможностей и угроз. В осознанном лидерстве он дополняется самопознанием и интуитивными инсайтами для получения целостной картины." }, category: "methodik", relatedTerms: ["strategieentwicklung", "entscheidungsmatrix", "szenarioplanung"], relatedServices: ["corporate", "coaching"] },
  { slug: "szenarioplanung", term: { de: "Szenarioplanung", en: "Scenario Planning", ru: "Сценарное планирование" }, definition: { de: "Szenarioplanung entwickelt verschiedene Zukunftsszenarien, um Organisationen auf unterschiedliche Entwicklungen vorzubereiten. Sie fördert strategische Flexibilität und ermöglicht proaktives Handeln statt reaktiver Krisensteuerung.", en: "Scenario planning develops various future scenarios to prepare organizations for different developments. It promotes strategic flexibility and enables proactive action instead of reactive crisis management.", ru: "Сценарное планирование разрабатывает различные сценарии будущего для подготовки организаций к разным вариантам развития. Оно способствует стратегической гибкости и позволяет действовать проактивно вместо реактивного управления кризисами." }, category: "methodik", relatedTerms: ["strategieentwicklung", "swot-analyse", "entscheidungsmatrix"], relatedServices: ["corporate"] },
  { slug: "kognitive-verzerrung", term: { de: "Kognitive Verzerrung", en: "Cognitive Bias", ru: "Когнитивное искажение" }, definition: { de: "Kognitive Verzerrungen sind systematische Denkfehler, die unsere Wahrnehmung und Entscheidungen unbewusst beeinflussen. Das Erkennen dieser Verzerrungen ist ein wesentlicher Schritt zu bewussteren, besseren Entscheidungen in Führung und Leben.", en: "Cognitive biases are systematic thinking errors that unconsciously influence our perception and decisions. Recognizing these biases is an essential step toward more conscious, better decisions in leadership and life.", ru: "Когнитивные искажения — систематические ошибки мышления, бессознательно влияющие на восприятие и решения. Распознавание этих искажений — важный шаг к более осознанным и лучшим решениям в лидерстве и жизни." }, category: "psychologie", relatedTerms: ["confirmation-bias", "dunning-kruger-effekt", "metacognition"], relatedServices: ["coaching", "seminare"] },
  { slug: "impostor-syndrom", term: { de: "Impostor-Syndrom", en: "Impostor Syndrome", ru: "Синдром самозванца" }, definition: { de: "Das Impostor-Syndrom beschreibt die innere Überzeugung, trotz objektiver Erfolge ein Hochstapler zu sein und den eigenen Erfolg nicht zu verdienen. Es betrifft besonders leistungsstarke Menschen und kann durch bewusste Coaching-Arbeit transformiert werden.", en: "Impostor syndrome describes the inner conviction of being a fraud despite objective success and not deserving one's own achievements. It particularly affects high achievers and can be transformed through conscious coaching work.", ru: "Синдром самозванца — внутреннее убеждение в том, что ты мошенник, несмотря на объективные успехи, и не заслуживаешь своих достижений. Он особенно затрагивает успешных людей и может быть трансформирован через осознанную коучинг-работу." }, category: "psychologie", relatedTerms: ["selbstbewusstsein", "selbstmitgefuehl", "kognitive-verzerrung"], relatedServices: ["coaching"] },
  { slug: "confirmation-bias", term: { de: "Confirmation Bias", en: "Confirmation Bias", ru: "Предвзятость подтверждения" }, definition: { de: "Confirmation Bias ist die Tendenz, Informationen so zu suchen und zu interpretieren, dass sie bestehende Überzeugungen bestätigen. Für Führungskräfte ist das Bewusstsein für diesen Bias entscheidend, um ausgewogene Entscheidungen zu treffen.", en: "Confirmation bias is the tendency to seek and interpret information in ways that confirm existing beliefs. For leaders, awareness of this bias is crucial for making balanced decisions.", ru: "Предвзятость подтверждения — тенденция искать и интерпретировать информацию так, чтобы она подтверждала существующие убеждения. Для руководителей осознание этого искажения критически важно для принятия взвешенных решений." }, category: "psychologie", relatedTerms: ["kognitive-verzerrung", "dunning-kruger-effekt", "entscheidungsstaerke"], relatedServices: ["coaching", "corporate"] },
  { slug: "dunning-kruger-effekt", term: { de: "Dunning-Kruger-Effekt", en: "Dunning-Kruger Effect", ru: "Эффект Даннинга-Крюгера" }, definition: { de: "Der Dunning-Kruger-Effekt beschreibt die kognitive Verzerrung, bei der Menschen mit geringem Wissen ihre Kompetenz überschätzen. Bewusstseinsentwicklung und ehrliches Feedback sind wirksame Gegenmaßnahmen zu diesem weitverbreiteten Phänomen.", en: "The Dunning-Kruger effect describes the cognitive bias where people with limited knowledge overestimate their competence. Consciousness development and honest feedback are effective countermeasures to this widespread phenomenon.", ru: "Эффект Даннинга-Крюгера описывает когнитивное искажение, при котором люди с ограниченными знаниями переоценивают свою компетентность. Развитие сознания и честная обратная связь — эффективные меры против этого распространённого феномена." }, category: "psychologie", relatedTerms: ["kognitive-verzerrung", "confirmation-bias", "selbstbewusstsein"], relatedServices: ["coaching"] },
  { slug: "selbstmitgefuehl", term: { de: "Selbstmitgefühl", en: "Self-Compassion", ru: "Самосострадание" }, definition: { de: "Selbstmitgefühl ist die Fähigkeit, sich selbst in schwierigen Momenten mit derselben Güte und Verständnis zu begegnen wie einem guten Freund. Es stärkt Resilienz, reduziert destruktive Selbstkritik und fördert nachhaltige Leistungsfähigkeit.", en: "Self-compassion is the ability to meet oneself in difficult moments with the same kindness and understanding as a good friend. It strengthens resilience, reduces destructive self-criticism, and promotes sustainable performance.", ru: "Самосострадание — способность относиться к себе в трудные моменты с той же добротой и пониманием, как к хорошему другу. Оно укрепляет стойкость, снижает деструктивную самокритику и способствует устойчивой работоспособности." }, category: "psychologie", relatedTerms: ["resilienz", "selbstbewusstsein", "achtsamkeit"], relatedServices: ["coaching"] },
  { slug: "grenzen-setzen", term: { de: "Grenzen setzen", en: "Setting Boundaries", ru: "Установление границ" }, definition: { de: "Grenzen setzen ist die Fähigkeit, klar zu definieren, was akzeptabel ist und was nicht. Gesunde Grenzen sind kein Zeichen von Schwäche, sondern von Selbstkenntnis und Selbstachtung — eine essenzielle Kompetenz für nachhaltige Führung.", en: "Setting boundaries is the ability to clearly define what is acceptable and what is not. Healthy boundaries are not a sign of weakness but of self-knowledge and self-respect — an essential competency for sustainable leadership.", ru: "Установление границ — способность чётко определять, что приемлемо, а что нет. Здоровые границы — не признак слабости, а самопознания и самоуважения, необходимая компетенция для устойчивого лидерства." }, category: "psychologie", relatedTerms: ["selbstbewusstsein", "burnout", "resilienz"], relatedServices: ["coaching"] },
  { slug: "psychologische-sicherheit", term: { de: "Psychologische Sicherheit", en: "Psychological Safety", ru: "Психологическая безопасность" }, definition: { de: "Psychologische Sicherheit ist das gemeinsame Vertrauen eines Teams, dass man Risiken eingehen kann, ohne bestraft oder beschämt zu werden. Sie ist der wichtigste Faktor für Teamleistung, Innovation und eine offene Fehlerkultur.", en: "Psychological safety is a team's shared belief that it is safe to take risks without being punished or shamed. It is the most important factor for team performance, innovation, and an open error culture.", ru: "Психологическая безопасность — общая уверенность команды в том, что можно рисковать без наказания или стыда. Это важнейший фактор командной эффективности, инноваций и открытой культуры ошибок." }, category: "psychologie", relatedTerms: ["fehlerkultur", "vertrauenskultur", "verletzlichkeit"], relatedServices: ["corporate", "coaching"] },
  { slug: "verletzlichkeit", term: { de: "Verletzlichkeit", en: "Vulnerability", ru: "Уязвимость" }, definition: { de: "Verletzlichkeit ist der Mut, sich authentisch und offen zu zeigen, auch wenn das Risiko besteht, verletzt zu werden. In der bewussten Führung ist sie keine Schwäche, sondern eine Quelle tiefer Verbindung und echten Vertrauens.", en: "Vulnerability is the courage to show oneself authentically and openly, even when there is risk of being hurt. In conscious leadership, it is not a weakness but a source of deep connection and genuine trust.", ru: "Уязвимость — мужество показать себя аутентично и открыто, даже когда есть риск быть раненым. В осознанном лидерстве это не слабость, а источник глубокой связи и настоящего доверия." }, category: "psychologie", relatedTerms: ["authentische-fuehrung", "psychologische-sicherheit", "selbstmitgefuehl"], relatedServices: ["coaching", "seminare"] },
  { slug: "stoizismus", term: { de: "Stoizismus", en: "Stoicism", ru: "Стоицизм" }, definition: { de: "Stoizismus ist eine antike Philosophie, die lehrt, zwischen dem zu unterscheiden, was wir kontrollieren können und was nicht. In der modernen Führung bietet er wertvolle Werkzeuge für emotionale Stabilität und gelassene Entscheidungsfindung.", en: "Stoicism is an ancient philosophy that teaches distinguishing between what we can control and what we cannot. In modern leadership, it offers valuable tools for emotional stability and calm decision-making.", ru: "Стоицизм — древняя философия, учащая различать то, что мы можем контролировать, и то, что не можем. В современном лидерстве он предлагает ценные инструменты для эмоциональной стабильности и спокойного принятия решений." }, category: "philosophie", relatedTerms: ["resilienz", "selbstregulation", "weisheit"], relatedServices: ["coaching", "keynotes"] },
  { slug: "existenzialismus", term: { de: "Existenzialismus", en: "Existentialism", ru: "Экзистенциализм" }, definition: { de: "Existenzialismus betont die Freiheit und Verantwortung des Einzelnen, sein Leben selbst zu gestalten. In der Coaching-Arbeit inspiriert er dazu, die eigene Existenz bewusst zu wählen statt von äußeren Umständen bestimmt zu werden.", en: "Existentialism emphasizes the freedom and responsibility of the individual to shape their own life. In coaching work, it inspires consciously choosing one's own existence rather than being determined by external circumstances.", ru: "Экзистенциализм подчёркивает свободу и ответственность человека в формировании собственной жизни. В коучинге он вдохновляет на осознанный выбор собственного существования, а не определяемость внешними обстоятельствами." }, category: "philosophie", relatedTerms: ["verantwortung", "autonomie", "sinn"], relatedServices: ["coaching"] },
  { slug: "pragmatismus", term: { de: "Pragmatismus", en: "Pragmatism", ru: "Прагматизм" }, definition: { de: "Pragmatismus bewertet Ideen und Ansätze nach ihrem praktischen Nutzen und ihrer Wirksamkeit. In der bewussten Führung verbindet er tiefes Verständnis mit konkretem Handeln und vermeidet sowohl leere Theorie als auch blinden Aktionismus.", en: "Pragmatism evaluates ideas and approaches by their practical utility and effectiveness. In conscious leadership, it combines deep understanding with concrete action, avoiding both empty theory and blind activism.", ru: "Прагматизм оценивает идеи и подходы по их практической полезности и эффективности. В осознанном лидерстве он соединяет глубокое понимание с конкретным действием, избегая как пустой теории, так и слепого активизма." }, category: "philosophie", relatedTerms: ["weisheit", "ethik", "entscheidungsstaerke"], relatedServices: ["coaching"] },
  { slug: "humanismus", term: { de: "Humanismus", en: "Humanism", ru: "Гуманизм" }, definition: { de: "Humanismus stellt die Würde, Freiheit und Entwicklung des Menschen in den Mittelpunkt. In der bewussten Führung bedeutet Humanismus, Menschen nicht als Ressourcen zu betrachten, sondern als Wesen mit einzigartigem Potenzial und inhärentem Wert.", en: "Humanism places human dignity, freedom, and development at the center. In conscious leadership, humanism means viewing people not as resources but as beings with unique potential and inherent value.", ru: "Гуманизм ставит достоинство, свободу и развитие человека в центр. В осознанном лидерстве гуманизм означает видеть в людях не ресурсы, а существ с уникальным потенциалом и неотъемлемой ценностью." }, category: "philosophie", relatedTerms: ["ethik", "werte", "servant-leadership"], relatedServices: ["coaching", "keynotes"] },
  { slug: "phronesis", term: { de: "Phronesis", en: "Phronesis", ru: "Фронезис" }, definition: { de: "Phronesis ist die aristotelische Tugend der praktischen Weisheit — die Fähigkeit, in konkreten Situationen das Richtige zu erkennen und zu tun. Sie verbindet theoretisches Wissen mit situativem Urteilsvermögen und moralischer Reife.", en: "Phronesis is the Aristotelian virtue of practical wisdom — the ability to recognize and do the right thing in concrete situations. It combines theoretical knowledge with situational judgment and moral maturity.", ru: "Фронезис — аристотелевская добродетель практической мудрости, способность распознавать и делать правильное в конкретных ситуациях. Она сочетает теоретическое знание с ситуативным суждением и моральной зрелостью." }, category: "philosophie", relatedTerms: ["weisheit", "tugend", "pragmatismus"], relatedServices: ["coaching"] },
  { slug: "eudaimonia", term: { de: "Eudaimonia", en: "Eudaimonia", ru: "Эвдемония" }, definition: { de: "Eudaimonia beschreibt ein gelungenes, erfülltes Leben im Sinne der Verwirklichung des eigenen Potenzials. Über kurzfristiges Glück hinaus strebt sie nach dauerhafter Blüte durch tugendhaftes Handeln und bewusstes Leben.", en: "Eudaimonia describes a successful, fulfilling life in the sense of realizing one's potential. Beyond short-term happiness, it strives for lasting flourishing through virtuous action and conscious living.", ru: "Эвдемония описывает удавшуюся, наполненную жизнь в смысле реализации собственного потенциала. За пределами кратковременного счастья она стремится к устойчивому расцвету через добродетельное действие и осознанную жизнь." }, category: "philosophie", relatedTerms: ["sinn", "tugend", "phronesis"], relatedServices: ["coaching"] },
  { slug: "logos", term: { de: "Logos", en: "Logos", ru: "Логос" }, definition: { de: "Logos bezeichnet in der philosophischen Tradition die Vernunft, das ordnende Prinzip und den Sinn hinter den Dingen. In der bewussten Führung steht Logos für die Fähigkeit, mit Klarheit und Logik das Wesentliche zu erkennen.", en: "Logos refers in the philosophical tradition to reason, the ordering principle, and the meaning behind things. In conscious leadership, Logos represents the ability to recognize the essential with clarity and logic.", ru: "Логос в философской традиции означает разум, упорядочивающий принцип и смысл вещей. В осознанном лидерстве Логос символизирует способность распознавать существенное с ясностью и логикой." }, category: "philosophie", relatedTerms: ["weisheit", "sinn", "kairos"], relatedServices: ["coaching", "keynotes"] },
  { slug: "kairos", term: { de: "Kairos", en: "Kairos", ru: "Кайрос" }, definition: { de: "Kairos bezeichnet den rechten Augenblick — den Moment, in dem Handeln besonders wirkungsvoll ist. Bewusste Führungskräfte entwickeln ein Gespür für Kairos und erkennen, wann der richtige Zeitpunkt für Entscheidungen und Veränderungen gekommen ist.", en: "Kairos refers to the opportune moment — the time when action is particularly effective. Conscious leaders develop a sense for Kairos and recognize when the right time for decisions and changes has come.", ru: "Кайрос означает благоприятный момент — время, когда действие особенно эффективно. Осознанные руководители развивают чувство Кайроса и распознают, когда наступает правильное время для решений и перемен." }, category: "philosophie", relatedTerms: ["logos", "intuition", "entscheidungsstaerke"], relatedServices: ["coaching"] },
];

export function getGlossaryBySlug(slug: string): GlossaryEntry | undefined {
  return glossaryEntries.find(e => e.slug === slug);
}

export function getGlossaryByCategory(category: string): GlossaryEntry[] {
  return glossaryEntries.filter(e => e.category === category);
}
